static int
print_symbol (int direct, int level, int last, Symbol *sym)
{
     struct output_symbol output_symbol;

     output_symbol.direct = direct;
     output_symbol.level = level;
     output_symbol.last = last;
     output_symbol.sym = sym;

     return output_driver[driver_index].handler(cflow_output_symbol,
						outfile, out_line,
						&output_symbol,
						output_driver[driver_index].handler_data);
}

static int
compare(const void *ap, const void *bp)
{
     Symbol * const *a = ap;
     Symbol * const *b = bp;
     return strcmp((*a)->name, (*b)->name);
}

static int
is_var(Symbol *symp)
{
     if (include_symbol(symp)) {
	  if (symp->type == SymIdentifier) 
	       return symp->storage == ExternStorage ||
	 	      symp->storage == StaticStorage;
	  else
	       return 1;
     }
     return 0;
}

int
symbol_is_function(Symbol *symp)
{
     return symp->type == SymIdentifier && symp->arity >= 0;
}

static void
clear_active(Symbol *sym)
{
     sym->active = 0;
}

void
print_refs(char *name, struct linked_list *reflist)
{
     Ref *refptr;
     struct linked_list_entry *p;

     for (p = linked_list_head(reflist); p; p = p->next) {
	  refptr = (Ref*)p->data;
	  fprintf(outfile, "%s   %s:%d\n",
		  name,
		  refptr->source,
		  refptr->line);
     }
}

static void
print_function(Symbol *symp)
{
     if (symp->source) {
	  fprintf(outfile, "%s * %s:%d %s\n",
		  symp->name,
		  symp->source,
		  symp->def_line,
		  symp->decl);
     }
     print_refs(symp->name, symp->ref_line);
}

static void
print_type(Symbol *symp)
{
     if (symp->source)
	  fprintf(outfile, "%s t %s:%d\n",
		  symp->name,
		  symp->source,
		  symp->def_line);
}

void
xref_output()
{
     Symbol **symbols, *symp;
     size_t i, num;

     num = collect_symbols(&symbols, is_var, 0);
     qsort(symbols, num, sizeof(*symbols), compare);

     /* produce xref output */
     for (i = 0; i < num; i++) {
	  symp = symbols[i];
	  switch (symp->type) {
	  case SymIdentifier:
	       print_function(symp);
	       break;
	  case SymToken:
	       print_type(symp);
	       break;
	  case SymUndefined:
	       break;
	  }
     }
     free(symbols);
}

static void
set_active(Symbol *sym)
{
     sym->active = out_line;
}

static int
is_printable(struct linked_list_entry *p)
{
     return p != NULL && include_symbol((Symbol*)p->data);
}

static int
is_last(struct linked_list_entry *p)
{
     while ((p = p->next))
	  if (is_printable(p))
	       return 0;
     return 1;
}

static void
direct_tree(int lev, int last, Symbol *sym)
{
     struct linked_list_entry *p;
     int rc;

     if (sym->type == SymUndefined
	 || (max_depth && lev >= max_depth)
	 || !include_symbol(sym))
	  return;

     rc = print_symbol(1, lev, last, sym);
     newline();
     if (rc || sym->active)
	  return;
     set_active(sym);
     for (p = linked_list_head(sym->callee); p; p = p->next) {
	  set_level_mark(lev+1, !is_last(p));
	  direct_tree(lev+1, is_last(p), (Symbol*)p->data);
     }
     clear_active(sym);
}

static void
inverted_tree(int lev, int last, Symbol *sym)
{
     struct linked_list_entry *p;
     int rc;

     if (sym->type == SymUndefined
	 || (max_depth && lev >= max_depth)
	 || !include_symbol(sym))
	  return;
     rc = print_symbol(0, lev, last, sym);
     newline();
     if (rc || sym->active)
	  return;
     set_active(sym);
     for (p = linked_list_head(sym->caller); p; p = p->next) {
	  set_level_mark(lev+1, !is_last(p));
	  inverted_tree(lev+1, is_last(p), (Symbol*)p->data);
     }
     clear_active(sym);
}

static void
tree_output()
{
     Symbol **symbols, *main_sym;
     size_t i, num;
     cflow_depmap_t depmap;

     /* Collect functions and assign them ordinal numbers */
     num = collect_functions(&symbols);
     for (i = 0; i < num; i++)
	  symbols[i]->ord = i;

     /* Create a dependency matrix */
     depmap = depmap_alloc(num);
     for (i = 0; i < num; i++) {
	  if (symbols[i]->callee) {
	       struct linked_list_entry *p;

	       for (p = linked_list_head(symbols[i]->callee); p;
		    p = p->next) {
		    Symbol *s = (Symbol*) p->data;
		    if (s->ord != -1 && symbol_is_function(s))
			 depmap_set(depmap, i, s->ord);
	       }		    
	  }
     }

     depmap_tc(depmap);

     /* Mark recursive calls */
     for (i = 0; i < num; i++)
	  if (depmap_isset(depmap, i, i))
	       symbols[i]->recursive = 1;
     free(depmap);
     free(symbols);

     /* Collect and sort all symbols */
     num = collect_symbols(&symbols, is_var, 0);
     qsort(symbols, num, sizeof(*symbols), compare);

     /* Produce output */
     begin();

     if (reverse_tree) {
	  for (i = 0; i < num; i++) {
	       inverted_tree(0, 0, symbols[i]);
	       separator();
	  }
     } else {
	  void *state;

	  main_sym = first_starter(&state);
	  if (main_sym) {
	       do {
		   direct_tree(0, 0, main_sym);
		   separator();
	       } while ((main_sym = next_starter(&state)) != NULL);
	  } else if (!all_functions) {
	       all_functions = 1;
	  }

	  if (all_functions) {
	       for (i = 0; i < num; i++) {
		    if (symbols[i]->flag != symbol_start
			&& symbols[i]->source
			&& (all_functions > 1 || symbols[i]->caller == NULL)) {
			 direct_tree(0, 0, symbols[i]);
			 separator();
		    }
	       }
	  }
     }

     end();

     free(symbols);
}

void
output()
{
     if (strcmp(outname, "-") == 0) {
	  outfile = stdout;
     } else {
	  outfile = fopen(outname, "w");
	  if (!outfile)
	       error(EX_FATAL, errno, _("cannot open file `%s'"), outname);
     } 

     set_level_mark(0, 0);
     if (print_option & PRINT_XREF) {
	  xref_output();
     }
     if (print_option & PRINT_TREE) {
	  eliminate_non_targets();
	  tree_output();
     }
     fclose(outfile);
}

static void
print_token(TOKSTK *tokptr)
{
     switch (tokptr->type) {
     case IDENTIFIER:
     case TYPE:
     case WORD:
     case MODIFIER:
     case STRUCT:
     case PARM_WRAPPER:
     case QUALIFIER:
     case OP:
	  fprintf(stderr, "`%s'", tokptr->token);
	  break;
     case LBRACE0:
     case LBRACE:
	  fprintf(stderr, "`{'");
	  break;
     case RBRACE0:
     case RBRACE:
	  fprintf(stderr, "`}'");
	  break;
     case EXTERN:
	  fprintf(stderr, "`extern'");
	  break;
     case STATIC:
	  fprintf(stderr, "`static'");
	  break;
     case TYPEDEF:
	  fprintf(stderr, "`typedef'");
	  break;
     case STRING:
	  fprintf(stderr, "\"%s\"", tokptr->token);
	  break;
     default:
	  fprintf(stderr, "`%c'", tokptr->type);
     }
}

static char *
token_type_str(int t)
{
     static char buf[80];
     switch (t) {
     case 0:
	  return "EOF";
     case WORD:
	  return "WORD";
     case LBRACE0:
	  return "'{'";
     case RBRACE0:
	  return "'}'";
     case IDENTIFIER:
	  return "IDENTIFIER";
     case EXTERN:
	  return "EXTERN";
     case STATIC:
	  return "STATIC";
     case TYPEDEF:
	  return "TYPEDEF";
     case STRUCT:
	  return "STRUCT";
     case MODIFIER:
	  return "MODIFIER";
     case OP:
	  return "OP";
     case UNION:
	  return "UNION";
     case ENUM:
	  return "ENUM";
     case LBRACE:
	  return "' {'";
     case RBRACE:
	  return "' }'";
     case MEMBER_OF:
	  return "MEMBER_OF";
     case TYPE:
	  return "TYPE";
     case STRING:
	  return "STRING";
     case PARM_WRAPPER:
	  return "PARM_WRAPPER";
     case QUALIFIER:
	  return "QUALIFIER";
     }
     if (isprint(t))
	  snprintf(buf, sizeof(buf), "'%c'(%d)", t, t);
     else
	  snprintf(buf, sizeof(buf), "%d", t);
     return buf;
}

static void
dbgtok(TOKSTK *t, int delim)
{
     if (delim)
	  fputc(delim, stderr);
     fprintf(stderr, "{ %s ", token_type_str(t->type));
     if (t->type)
	  fprintf(stderr, ", %s, %d ", t->token ? t->token : "NULL", t->line);
     fputc('}', stderr);
}

static void
debugtoken(TOKSTK *t, char *fmt, ...)
{
     if (debug > 1) {
	  va_list ap;
	  int i;

	  if (fmt) {
	       va_start(ap, fmt);
	       vfprintf(stderr, fmt, ap);
	       va_end(ap);
	       fprintf(stderr, ": ");
	  }
	  if (t) {
	       dbgtok(t, 0);
	       fprintf(stderr, "; ");
	  }
	  fprintf(stderr, "%d: {", curs);
	  for (i = curs; i < tos; i++)
	       dbgtok(token_stack + i, i == curs ? 0 : ',');
	  fprintf(stderr, "}\n");
     }
}

static void
file_error(char *msg, TOKSTK *tokptr)
{
    fprintf(stderr, "%s:%d: %s", filename, tok.line, msg);
    if (tokptr) {
	fprintf(stderr, _(" near "));
	print_token(tokptr);
    }
    fprintf(stderr, "\n");
}

void
mark(Stackpos pos)
{
     pos[0] = curs;
     if (debug > 1)
	  fprintf(stderr, "marking stack at %d\n", curs);
}

void
restore(Stackpos pos)
{
     curs = pos[0];
     if (curs) {
	  tok = token_stack[curs-1];
	  debugtoken(&tok, "restored stack");
     }
}

void
tokdel(int beg, int end)
{
     if (end >= beg) {
	  if (end < tos)
	       memmove(token_stack + beg, token_stack + end + 1,
		       (tos - end - 1) * sizeof(token_stack[0]));
	  tos -= (end - beg + 1);
     }
}

void
tokins(int pos, int type, int line, char *token)
{
     if (++tos == token_stack_length) {
	  token_stack_length += token_stack_increase;
	  token_stack = xrealloc(token_stack,
				 token_stack_length*sizeof(*token_stack));
     }
     memmove(token_stack + pos + 1, token_stack + pos,
	     (tos - pos - 1) * sizeof(token_stack[0]));
     token_stack[pos].type = type;
     token_stack[pos].token = token;
     token_stack[pos].line = line;
     debugtoken(&token_stack[pos], "insert at %d", pos);
}

void
tokpush(int type, int line, char *token)
{
     token_stack[tos].type = type;
     token_stack[tos].token = token;
     token_stack[tos].line = line;
     if (++tos == token_stack_length) {
	  token_stack_length += token_stack_increase;
	  token_stack = xrealloc(token_stack,
				 token_stack_length*sizeof(*token_stack));
     }
}

void
cleanup_stack()
{
     int delta = tos - curs;

     if (delta > 0)
	  memmove(token_stack, token_stack+curs, delta*sizeof(token_stack[0]));
     else if (delta < 0) /* Invalid input */
	  delta = 0;
     tos = delta;
     curs = 0;
}

void
clearstack()
{
     tos = curs = 0;
}

int
nexttoken()
{
     int type;

     if (curs == tos) {
	  type = get_token();
	  tokpush(type, line_num, yylval.str);
	  yylval.str = NULL;
     }
     tok = token_stack[curs];
     curs++;
     debugtoken(&tok, "next token");
     return tok.type;
}

int
putback()
{
     if (curs == 0) {
	  error(0, 0, _("INTERNAL ERROR: cannot return token to stream"));
	  abort();
     }
     curs--;
     if (curs > 0) {
	  tok = token_stack[curs-1];
     } else
	  tok.type = 0;
     debugtoken(&tok, "putback");
     return tok.type;
}

void
init_parse()
{
     obstack_init(&text_stk);
     token_stack = xmalloc(token_stack_length*sizeof(*token_stack));
     clearstack();
}

void
save_token(TOKSTK *tokptr)
{
     int len;

     switch (tokptr->type) {
     case IDENTIFIER:
     case TYPE:
     case STRUCT:
     case PARM_WRAPPER:
     case WORD:
     case QUALIFIER:
	  if (need_space)
	       obstack_1grow(&text_stk, ' ');
	  len = strlen(tokptr->token);
	  obstack_grow(&text_stk, tokptr->token, len);
	  need_space = 1;
	  break;
     case MODIFIER:
	  if (need_space)
	       obstack_1grow(&text_stk, ' ');
	  if (tokptr->token[0] == '*')
	       need_space = 0;
	  else
	       need_space = 1;
	  len = strlen(tokptr->token);
	  obstack_grow(&text_stk, tokptr->token, len);
	  break;
     case EXTERN: /* storage class specifiers are already taken care of */
     case STATIC:
	  break;
     case ',':
	  obstack_1grow(&text_stk, ',');
	  need_space = 1;
	  break;
     case '(':
	  if (need_space)
	       obstack_1grow(&text_stk, ' ');
	  obstack_1grow(&text_stk, tokptr->type);
	  need_space = 0;
	  break;
     case ')':
	  obstack_1grow(&text_stk, tokptr->type);
	  need_space = 1;
	  break;
     case '[':
     case ']':
	  obstack_1grow(&text_stk, tokptr->type);
	  need_space = 0;
	  break;
     case LBRACE:
     case LBRACE0:
	  if (need_space)
	       obstack_1grow(&text_stk, ' ');
	  obstack_1grow(&text_stk, '{');
	  need_space = 1;
	  break;
     case RBRACE:
     case RBRACE0:
	  if (need_space)
	       obstack_1grow(&text_stk, ' ');
	  obstack_1grow(&text_stk, '}');
	  need_space = 1;
	  break;
     case OP:
	  obstack_1grow(&text_stk, ' ');
	  obstack_grow(&text_stk, tokptr->token, strlen(tokptr->token));
	  need_space = 1;
	  break;
     default:
	  if (verbose)
	       file_error(_("unrecognized definition"), tokptr);
     }
}

void
save_stack()
{
     mark(start_pos);
     save_end = curs - 1;
}

void
undo_save_stack()
{
     save_end = -1;
}

int
save_stack_is_empty()
{
     return save_end <= 0;
}

char *
finish_save_stack(char *name)
{
     int i;
     int level = 0;
     int found_ident = !omit_symbol_names_option;

     need_space = 0;
     for (i = 0; i < save_end ; i++) {
	  switch (token_stack[i].type) {
	  case '(':
	       if (omit_arguments_option) {
		    if (level == 0) {
			 save_token(token_stack+i);
		    }
		    level++;
	       }
	       break;
	  case ')':
	       if (omit_arguments_option)
		    level--;
	       break;
	  case IDENTIFIER:
	       if (!found_ident && strcmp (name, token_stack[i].token) == 0) {
		    need_space = 1;
		    found_ident = 1;
		    continue;
	       }
	  }
	  if (level == 0)
	       save_token(token_stack+i);
     }
     obstack_1grow(&text_stk, 0);
     return obstack_finish(&text_stk);
}

void
skip_to(int c)
{
     while (nexttoken()) {
	  if (tok.type == c)
	       break;
     }
}

static void
push_balance_state(struct balance_state **ptos, int idx, int level)
{
     struct balance_state *state = xmalloc(sizeof(state[0]));
     state->idx = idx;
     state->level = level;
     state->prev = *ptos;
     *ptos = state;
}

static void
pop_balance_state(struct balance_state **ptos, int *idx, int *level)
{
     struct balance_state *state = *ptos;
     *idx = state->idx;
     *level = state->level;
     *ptos = state->prev;
     free(state);
}

static void
free_balance_stack(struct balance_state **ptos)
{
     int i, j;
     while (*ptos)
	  pop_balance_state(ptos, &i, &j);
}

static int
find_closing_paren(int open_tok, int level)
{
     static char oparen[] = "([{";
     static char cparen[] = ")]}";
     int idx;
     char *p = strchr(oparen,  open_tok);
     struct balance_state *tos = NULL;

     if (!p) {
	  error(EX_SOFTWARE, 0, "%s:%d: INTERNAL ERROR: malformed call to %s",
		__FILE__, __LINE__, __func__);
	  abort();
     }
     idx = p - oparen;

     if (level == 0) {
	  if (nexttoken() != open_tok) {
	       return 1;
	  }
	  level++;
     }
     while (nexttoken()) {
	  if (tok.type == LBRACE0)
	       tok.type = '{';
	  else if (tok.type == RBRACE0)
	       tok.type = '}';

	  if (tok.type == oparen[idx])
	       level++;
	  else if (tok.type == cparen[idx]) {
	       if (--level == 0) {
		    if (tos == NULL)
			 return 0;
		    else
			 pop_balance_state(&tos, &idx, &level);
	       }
	  } else if ((p = strchr(oparen, tok.type)) != NULL) {
	       push_balance_state(&tos, idx, level);
	       idx = p - oparen;
	       level = 1;
	  }
     }
     free_balance_stack(&tos);
     return -1;
}

static inline int
skip_balanced(int open_tok, int level)
{
     int rc = find_closing_paren(open_tok, level);
     if (rc == 0)
	  nexttoken();
     return rc;
}

int
yyparse()
{
     Ident identifier;

     level = 0;
     caller = NULL;
     clearstack();
     while (nexttoken()) {
	  identifier.storage = ExternStorage;
	  switch (tok.type) {
	  case 0:
	       return 0;
	  case QUALIFIER:
	       continue;
	  case TYPEDEF:
	       parse_typedef();
	       break;
	  case DECLARATION:
	       skip_declaration();
	       break;
	  case EXTERN:
	       identifier.storage = ExplicitExternStorage;
	       nexttoken();
	       parse_declaration(&identifier, 0);
	       break;
	  case STATIC:
	       identifier.storage = StaticStorage;
	       nexttoken();
	       /* FALLTHRU */
	  default:
	       parse_declaration(&identifier, 0);
	       break;
	  }
	  cleanup_stack();
     }
     return 0;
}

static int
is_function()
{
     Stackpos sp;
     int res = 0;

     mark(sp);
     while (1) {
	  switch (tok.type) {
	  case QUALIFIER:
	  case TYPE:
	  case IDENTIFIER:
	  case MODIFIER:
	  case STATIC:
	  case EXTERN:
	  case STRUCT:
	  case UNION:
	  case ENUM:
	       nexttoken();
	       continue;
	  case PARM_WRAPPER:
	       if (skip_balanced('(', 0) == -1)
		    file_error(_("unexpected end of file in declaration"),
			       NULL);
	       continue;
	  case '(':
	       res = nexttoken() != MODIFIER;
	       break;
	  default:
	       break;
	  }
	  break;
     }

     restore(sp);
     return res;
}

void
parse_declaration(Ident *ident, int parm)
{
     if (is_function())
	  parse_function_declaration(ident, parm);
     else
	  parse_variable_declaration(ident, parm);
     delete_parms(parm_level);
}

void
skip_declaration(void)
{
     if (skip_balanced('(', 0) == -1)
	  file_error(_("unexpected end of file in declaration"), NULL);
     if (tok.type != ';')
	  putback();
}

void
expression()
{
     char *name;
     int line;
     int parens_lev;

     parens_lev = 0;
     while (1) {
	  switch (tok.type) {
	  case ';':
	       return;
	  case PARM_WRAPPER:
	       if (skip_balanced('(', 0) == -1) {
		    file_error(_("unexpected end of file in expression"),
			       NULL);
		    return;
	       }
	       putback();
	       break;
	  case LBRACE:
	  case LBRACE0:
	  case RBRACE:
	  case RBRACE0:
	       putback();
	       return;
	  case ',':
	       if (parens_lev == 0)
		    return;
	       break;
	  case 0:
	       if (verbose)
		    file_error(_("unexpected end of file in expression"),
			       NULL);
	       return;

	  case IDENTIFIER:
	       name = tok.token;
	       line = tok.line;
	       nexttoken();
	       if (tok.type == '(') {
		    call(name, line);
		    parens_lev++;
	       } else {
		    reference(name, line);

		    /* MEMBER_OF can be preceded by a closing paren, as in
		       (*a)->b
		    */
		    while (parens_lev > 0 && tok.type == ')') {
			 parens_lev--;
			 nexttoken();
		    }

		    if (tok.type == MEMBER_OF) {
			 nexttoken();
		    } else {
			 putback();
		    }
	       }
	       break;
	  case '(':
	       /* maybe typecast */
	       if (nexttoken() == TYPE || tok.type == STRUCT) {
		    if (skip_balanced('(', 1) == -1) {
			 file_error(_("unexpected end of file in expression"),
				    NULL);
			 return;
		    }
		    if (tok.type == LBRACE || tok.type == LBRACE0) {
			 if (skip_balanced('{', 1) == -1) {
			      file_error(_("unexpected end of file in expression"),
					 NULL);
			      return;
			 }
		    }
	       } else {
		    parens_lev++;
	       }
	       putback();
	       break;
	  case ')':
	       parens_lev--;
	       break;
	  case MEMBER_OF:
	       nexttoken();
	       break;
	  }
	  nexttoken();
     }
}

void
parse_function_declaration(Ident *ident, int parm)
{
     int error_recovery = 0;
     ident->type_end = -1;
     parse_knr_dcl(ident);

 restart:
     switch (tok.type) {
     case ')':
	  if (parm)
	       break;
	  /*FALLTHROUGH*/
     default:
	  if (error_recovery)
	       nexttoken();
	  else {
	       if (verbose)
		    file_error(_("expected `;'"), &tok);
	       error_recovery = 1;
	  }
	  goto restart;

     case ';':
     case ',':
	  break;
     case LBRACE0:
     case LBRACE:
	  if (ident->name) {
	       caller = lookup(ident->name);
	       if (caller &&
		   (caller->storage == AutoStorage || caller->flag == symbol_target))
		    caller = NULL;
	       func_body();
	  }
	  break;
     case 0:
	  if (verbose)
	       file_error(_("unexpected end of file in declaration"), NULL);
     }
}

int
fake_struct(Ident *ident)
{
     while (tok.type == QUALIFIER &&
	    (strcmp(tok.token, "const") == 0 ||
	     strcmp(tok.token, "volatile") == 0))
	  nexttoken();
     ident->type_end = -1;
     if (tok.type == STRUCT) {
	  if (nexttoken() == IDENTIFIER) {
	       ident->type_end = curs;
	  }
	  putback();
	  skip_struct();
	  if (tok.type == IDENTIFIER || tok.type == MODIFIER ||
	      tok.type == QUALIFIER)
	       putback();
	  else if (tok.type == TYPE) {
	       /*
		* Duplicate typedef is allowed as long as both definitions
		* coincide.  Put the token back as an identifier, so that
		* dcl parses it correctly.
		*/
	       token_stack[curs-1].type = IDENTIFIER;
	       putback();
	  } else if (tok.type == '(')
	       return 0;
	  else if (tok.type != ';')
	       file_error(_("missing `;' after struct declaration"), &tok);
	  return 1;
     }
     return 0;
}

void
parse_variable_declaration(Ident *ident, int parm)
{
     Stackpos sp;

     mark(sp);
     ident->type_end = -1;

     while (tok.type == QUALIFIER)
	  nexttoken();

     if (tok.type == STRUCT || tok.type == UNION) {
	  if (nexttoken() == IDENTIFIER) {
	       ident->type_end = curs;
	  }
	  putback();
	  skip_struct();
	  while (tok.type == MODIFIER || tok.type == QUALIFIER)
	       nexttoken();
	  if (tok.type == IDENTIFIER) {
	       if (ident->type_end == -1) {
		    int pos = curs-1;
		    restore(sp);
		    /* there was no tag. Insert { ... } */
		    tokdel(curs, pos - 1);
		    tokins(curs, IDENTIFIER, tok.line, "{ ... }");
		    debugtoken(&tok, "modified stack");
	       }
	  } else {
	       if (tok.type == ';')
		    return;
	       restore(sp);
	  }
     }
 again:
     parse_dcl(ident, 0);

 select:
     switch (tok.type) {
     case ')':
	  if (parm)
	       break;
	  /*FALLTHROUGH*/
     default:
	  if (verbose)
	       file_error(_("expected `;'"), &tok);
	  /* FIXME: should putback() here? */
	  break;
     case ';':
	  break;
     case ',':
	  if (parm)
	       break;
	  tos = ident->type_end;
	  restore(sp);
	  goto again;
     case '=':
	  nexttoken();
	  switch (tok.type) {
	  case LBRACE:
	  case LBRACE0:
	       initializer_list();
	       goto select;

	  case RBRACE:
	  case RBRACE0:
	       if (verbose)
		    file_error(_("expected expression"), &tok);
	       break;

	  default:
	       expression();
	       goto select;
	  }
	  break;

     case LBRACE0:
     case LBRACE:
	  func_body();
	  break;
     case 0:
	  if (verbose)
	       file_error(_("unexpected end of file in declaration"), NULL);
     }
}

void
initializer_list()
{
     int lev = 0;
     while (1) {
	  switch (tok.type) {
	  case LBRACE:
	  case LBRACE0:
	       lev++;
	       break;
	  case RBRACE:
	  case RBRACE0:
	       if (--lev <= 0) {
		    nexttoken();
		    return;
	       }
	       break;
	  case 0:
	       file_error(_("unexpected end of file in initializer list"),
			  NULL);
	       return;
	  case ',':
	       break;
	  default:
	       expression();
	       break;
	  }
	  nexttoken();
     }
}

void
parse_knr_dcl(Ident *ident)
{
     ident->type_end = -1;
     parse_dcl(ident, !strict_ansi);
}

void
skip_struct()
{
     if (nexttoken() == IDENTIFIER) {
	  nexttoken();
     } else if (tok.type == ';')
	  return;

     if (tok.type == LBRACE || tok.type == LBRACE0) {
	  if (skip_balanced('{', 1) == -1) {
	       file_error(_("unexpected end of file in struct"), NULL);
	       return;
	  }
     }

     while (tok.type == PARM_WRAPPER) {
	  if (skip_balanced('(', 0) == -1) {
	      file_error(_("unexpected end of file in struct"), NULL);
	      return;
	  }
     }
}

void
parse_typedef()
{
     Ident ident;

     ident.name = NULL;
     ident.type_end = -1;
     ident.parmcnt = -1;
     ident.line = -1;
     ident.storage = AnyStorage;

     nexttoken();
     if (!fake_struct(&ident))
	  putback();

     dcl(&ident);
     if (ident.name)
	  declare_type(&ident);
}

void
parse_dcl(Ident *ident, int maybe_knr)
{
     ident->parmcnt = -1;
     ident->name = NULL;
     putback();
     dcl(ident);
     save_stack();
     if (ident->name)
	  declare(ident, maybe_knr);
     else
	  undo_save_stack();
}

int
dcl(Ident *idptr)
{
     while (nexttoken() != 0 && tok.type != '(') {
	  if (tok.type == MODIFIER) {
	       if (idptr && idptr->type_end == -1)
		    idptr->type_end = curs-1;
	  } else if (tok.type == PARM_WRAPPER) {
	       if (skip_balanced('(', 0) == -1) {
		    file_error(_("unexpected end of file in function declaration"),
			       NULL);
		    return 1;
	       }
	       putback();
	  } else if (tok.type == IDENTIFIER) {
	       int type;

	       while (tok.type == IDENTIFIER)
		    nexttoken();
	       type = tok.type;
	       putback();
	       if (!(type == TYPE ||
		     type == MODIFIER || type == QUALIFIER))
		    break;
	  } else if (tok.type == ')' || tok.type == ';') {
	       return 1;
	  }
     }
     if (idptr && idptr->type_end == -1)
	  idptr->type_end = curs-1;
     return dirdcl(idptr);
}

int
getident(Ident *idptr, int **parm_ptr)
{
     Stackpos pos;
     int bc = 0;

     mark(pos);
     do {
	  ++bc;
	  if (nexttoken() == 0) {
	       if (verbose)
		    file_error(_("unexpected end of file"), NULL);
	       return -1;
	  }
     } while (tok.type == '(');

     if (tok.type == IDENTIFIER) {
	  char *name = tok.token;
	  int line = tok.line;

	  while (bc > 0) {
	       if (nexttoken() == 0) {
		    if (verbose)
			 file_error(_("unexpected end of file"), NULL);
		    return -1;
	       }
	       if (tok.type == ')')
		    --bc;
	       else
		    break;
	  }

	  if (bc == 0) {
	       if (idptr) {
		    idptr->name = name;
		    idptr->line = line;
		    *parm_ptr = &idptr->parmcnt;
	       }
	       return 0;
	  }
     }
     restore(pos);
     return 1;
}

int
dirdcl(Ident *idptr)
{
     int wrapper = 0;
     int *parm_ptr = NULL;

     if (tok.type == '(') {
	  switch (getident(idptr, &parm_ptr)) {
	  case 0:
	       break;

	  case -1:
	       return 1;

	  case 1:
	       dcl(idptr);
	       if (tok.type != ')' && verbose) {
		    file_error(_("expected `)'"), &tok);
		    return 1;
	       }
	       break;
	  }
     } else if (tok.type == IDENTIFIER) {
	  if (idptr) {
	       idptr->name = tok.token;
	       idptr->line = tok.line;
	       parm_ptr = &idptr->parmcnt;
	  }
     }

     if (nexttoken() == PARM_WRAPPER) {
	  wrapper = 1;
	  nexttoken(); /* read '(' */
     } else
	  putback();

     while (nexttoken() == '[' || tok.type == '(') {
	  if (tok.type == '[') {
	       if (find_closing_paren('[', 1) == -1) {
		    file_error(_("unexpected end of file in declaration"),
			       NULL);
		    return -1;
	       }
	  } else {
	       maybe_parm_list(parm_ptr);
	       if (tok.type != ')' && verbose) {
		    file_error(_("expected `)'"), &tok);
		    return 1;
	       }
	  }
     }
     if (wrapper)
	  nexttoken(); /* read ')' */

     while (tok.type == PARM_WRAPPER) {
	  if (skip_balanced('(', 0) == -1)
	       file_error(_("unexpected end of file in function declaration"),
			  NULL);
     }

     return 0;
}

int
parmdcl(Ident *idptr)
{
     int type;

     while (nexttoken() != 0 && tok.type != '(') {
	  if (tok.type == MODIFIER) {
	       if (idptr && idptr->type_end == -1)
		    idptr->type_end = curs-1;
	  } else if (tok.type == IDENTIFIER) {
	       while (tok.type == IDENTIFIER)
		    nexttoken();
	       type = tok.type;
	       putback();
	       if (type != MODIFIER)
		    break;
	  } else if (tok.type == ')' || tok.type == ',')
	       return 0;
     }
     if (idptr && idptr->type_end == -1)
	  idptr->type_end = curs-1;
     return dirdcl(idptr);
}

void
maybe_parm_list(int *parm_cnt_return)
{
     int parmcnt = 0;
     Ident ident;
     int level;

     parm_level++;
     while (nexttoken()) {
	  switch (tok.type) {
	  case ')':
	       if (parm_cnt_return)
		    *parm_cnt_return = parmcnt;
	       parm_level--;
	       return;
	  case ',':
	       break;
	  case QUALIFIER:
	  case IDENTIFIER:
	  case MODIFIER: /* unsigned * */
	  case STRUCT:
	  case UNION:
	  case TYPE:
	       parmcnt++;
	       ident.storage = AutoStorage;
	       parse_declaration(&ident, 1);
	       putback();
	       break;
	  default:
	       if (verbose)
		    file_error(_("unexpected token in parameter list"),
			       &tok);
	       level = 0;
	       do {
		    if (tok.type == '(')
			 level++;
		    else if (tok.type == ')') {
			 if (level-- == 0)
			      break;
		    }
	       } while (nexttoken());
		    ;
	       putback();
	  }
     }
     if (verbose)
	  file_error(_("unexpected end of file in parameter list"), NULL);
}

void
func_body()
{
     Ident ident;

     level++;
     move_parms(level);
     while (level) {
	  cleanup_stack();
	  nexttoken();
	  switch (tok.type) {
	  default:
	       expression();
	       break;
	  case STATIC:
	       ident.storage = StaticStorage;
	       nexttoken();
	       parse_variable_declaration(&ident, 0);
	       break;
	  case TYPE:
	  case STRUCT:
	       ident.storage = AutoStorage;
	       parse_variable_declaration(&ident, 0);
	       break;
	  case EXTERN:
	       ident.storage = ExplicitExternStorage;
	       parse_declaration(&ident, 0);
	       break;
	  case LBRACE0:
	  case LBRACE:
	       level++;
	       break;
	  case RBRACE0:
	       if (use_indentation) {
		    if (verbose && level != 1)
			 file_error(_("forced function body close"), NULL);
		    for ( ; level; level--) {
			 delete_autos(level);
		    }
		    break;
	       }
	       /* else: */
	       /* FALLTHRU */
	  case RBRACE:
	       delete_autos(level);
	       level--;
	       break;
	  case 0:
	       if (verbose)
		    file_error(_("unexpected end of file in function body"),
			       NULL);
	       goto end;
	  }
     }
end:
     caller = NULL;
}

int
get_knr_args(Ident *ident)
{
     int parmcnt, stop;
     Stackpos sp, new_sp;
     Ident id;

     switch (tok.type) {
     case QUALIFIER:
     case IDENTIFIER:
     case TYPE:
     case STRUCT:
	  /* maybe K&R function definition */

	  mark(sp);
	  parmcnt = 0;

	  for (stop = 0; !stop && parmcnt < ident->parmcnt;
	       nexttoken()) {
	       id.type_end = -1;
	       switch (tok.type) {
	       case LBRACE:
	       case LBRACE0:
		    putback();
		    stop = 1;
		    break;
	       case TYPE:
	       case QUALIFIER:
	       case IDENTIFIER:
	       case STRUCT:
		    putback();
		    mark(new_sp);
		    if (dcl(&id) == 0) {
			 parmcnt++;
			 if (tok.type == ',') {
			      do {
				   tos = id.type_end; /* ouch! */
				   restore(new_sp);
				   dcl(&id);
			      } while (tok.type == ',');
			 } else if (tok.type != ';')
			      putback();
			 break;
		    }
		    /* else */
		    /* FALLTHRU */
	       default:
		    restore(sp);
		    return 1;
	       }
	  }
     }
     return 0;
}

void
declare(Ident *ident, int maybe_knr)
{
     Symbol *sp;

     if (ident->storage == AutoStorage) {
	  undo_save_stack();
	  sp = install_ident(ident->name, ident->storage);
	  if (parm_level) {
	       sp->level = parm_level;
	       sp->flag = symbol_parm;
	  } else
	       sp->level = level;
	  sp->arity = -1;
	  return;
     }

     if ((ident->parmcnt >= 0
	  && (!maybe_knr || get_knr_args(ident) == 0)
	  && !(tok.type == LBRACE || tok.type == LBRACE0 || tok.type == TYPE
	       || tok.type == PARM_WRAPPER))
	 || (ident->parmcnt < 0 && ident->storage == ExplicitExternStorage)
	 || save_stack_is_empty()) {
	  undo_save_stack();
	  /* add_external()?? */
	  return;
     }

     sp = get_symbol(ident->name);
     if (sp->source) {
	  if (ident->storage == StaticStorage
	      && (sp->storage != StaticStorage || level > 0)) {
	       sp = install_ident(ident->name, ident->storage);
	  } else {
	       if (sp->arity >= 0)
		    error_at_line(0, 0, filename, ident->line,
				  _("%s/%d redefined"),
				  ident->name, sp->arity);
	       else
		    error_at_line(0, 0, filename, ident->line,
				  _("%s redefined"),
				  ident->name);
	       error_at_line(0, 0, sp->source, sp->def_line,
			     _("this is the place of previous definition"));
	  }
     }

     sp->type = SymIdentifier;
     sp->arity = ident->parmcnt;
     ident_change_storage(sp,
			  (ident->storage == ExplicitExternStorage) ?
			  ExternStorage : ident->storage);
     sp->decl = finish_save_stack(ident->name);
     sp->source = filename;
     sp->def_line = ident->line;
     sp->level = level;
     if (debug)
	  fprintf(stderr, _("%s:%d: %s/%d defined to %s\n"),
		 filename,
		 line_num,
		 ident->name, ident->parmcnt,
		 sp->decl);
}

void
declare_type(Ident *ident)
{
     Symbol *sp;

     undo_save_stack();
     sp = lookup(ident->name);
     for ( ; sp; sp = sp->next)
	  if (sp->type == SymToken && sp->token_type == TYPE)
	       break;
     if (!sp)
	  sp = install(ident->name, INSTALL_UNIT_LOCAL);
     sp->type = SymToken;
     sp->token_type = TYPE;
     sp->source = filename;
     sp->def_line = ident->line;
     sp->ref_line = NULL;
     if (debug)
	  fprintf(stderr, _("%s:%d: type %s\n"), filename, line_num,
		  ident->name);
}

Symbol *
get_symbol(char *name)
{
     Symbol *sp = lookup(name) ;

     if (sp) {
	  for (; sp; sp = sp->next) {
	       if (sp->flag == symbol_start ||
		   sp->flag == symbol_target ||
		   sp->type == SymIdentifier)
		    break;
	  }
	  if (sp) {
	       if ((sp->flag == symbol_start || sp->flag == symbol_target)
		   && sp->type == SymUndefined) {
		    init_ident(sp, ExternStorage);
	       }
	       return sp;
	  }
     }
     return install_ident(name, ExternStorage);
}

Symbol *
add_reference(char *name, int line)
{
     Symbol *sp = get_symbol(name);
     Ref *refptr;

     if (sp->storage == AutoStorage
	 || (sp->storage == StaticStorage && globals_only()))
	  return NULL;
     refptr = xmalloc(sizeof(*refptr));
     refptr->source = filename;
     refptr->line = line;
     if (!sp->ref_line)
	  sp->ref_line = linked_list_create(free);
     linked_list_append(&sp->ref_line, refptr);
     return sp;
}

void
call(char *name, int line)
{
     Symbol *sp;

     sp = add_reference(name, line);
     if (!sp)
	  return;
     if (sp->arity < 0)
	  sp->arity = 0;
     if (caller) {
	  if (!data_in_list(caller, sp->caller))
	       linked_list_append(&sp->caller, caller);
	  if (!data_in_list(sp, caller->callee))
	       linked_list_append(&caller->callee, sp);
     }
}

void
reference(char *name, int line)
{
     Symbol *sp = add_reference(name, line);
     if (!sp)
	  return;
     if (caller) {
	  if (!data_in_list(caller, sp->caller))
	       linked_list_append(&sp->caller, caller);
	  if (!data_in_list(sp, caller->callee))
	       linked_list_append(&caller->callee, sp);
     }
}

void
reset_static_caller(void)
{
     if (caller &&
	 (caller->storage == StaticStorage || caller->flag == symbol_local))
	  caller = NULL;
}

static void
print_symbol_type(FILE *outfile, Symbol *sym)
{
     if (sym->decl) 
	  fprintf(outfile, "%s, <%s %d>",
		  sym->decl,
		  sym->source,
		  sym->def_line);
     else
	  fprintf(outfile, "<>");
}

static int
print_symbol(FILE *outfile, int line, struct output_symbol *s)
{
     print_level(s->level, s->last);
     fprintf(outfile, "%s: ", s->sym->name);

     if (brief_listing) {
	  if (s->sym->expand_line) {
	       fprintf(outfile, "%d", s->sym->expand_line);
	       return 1;
	  } else if (s->sym->callee)
	       s->sym->expand_line = line;
     }
     print_symbol_type(outfile, s->sym);
     return 0;
}

int
posix_output_handler(cflow_output_command cmd,
		     FILE *outfile, int line,
		     void *data, void *handler_data)
{
     switch (cmd) {
     case cflow_output_init:
	  /* Additional check for consistency */
	  if (emacs_option)
	       error(EX_USAGE, 0,
		     _("--format=posix is not compatible with --emacs"));
	  brief_listing = print_line_numbers = omit_symbol_names_option = 1;
	  break;
     case cflow_output_begin:
     case cflow_output_end:
     case cflow_output_separator:
	  break;
     case cflow_output_newline:
	  fprintf(outfile, "\n");
	  break;
     case cflow_output_text:
	  fprintf(outfile, "%s", (char*) data);
	  break;
     case cflow_output_symbol:
	  return print_symbol(outfile, line, data);
     }
     return 0;
}

static void
symbol_unlink_from_list(Symbol *sp)
{
     if (sp->entry) {
	  linked_list_unlink(sp->entry->list, sp->entry);
	  sp->entry = NULL;
     }
}

static void
append_symbol(struct linked_list **plist, Symbol *sp)
{
     symbol_unlink_from_list(sp);
     if (!data_in_list(sp, *plist)) {
	  linked_list_append(plist, sp);
	  sp->entry = (*plist)->tail;
     }
}

static size_t
hash_symbol_hasher(void const *data, size_t n_buckets)
{
     struct table_entry const *t = data;
     if (!t->sym)
	  return ((size_t) data) % n_buckets;
     return hash_string(t->sym->name, n_buckets);
}

static bool
hash_symbol_compare(void const *data1, void const *data2)
{
     struct table_entry const *t1 = data1;
     struct table_entry const *t2 = data2;
     return t1->sym && t2->sym && strcmp(t1->sym->name, t2->sym->name) == 0;
}

Symbol *
lookup(const char *name)
{
     Symbol s, *sym;
     struct table_entry t, *tp;

     if (!symbol_table)
	  return NULL;
     s.name = (char*) name;
     t.sym = &s;
     tp = hash_lookup(symbol_table, &t);
     if (tp) {
	  sym = tp->sym;
	  while (sym->type == SymToken && sym->flag == symbol_alias)
	       sym = sym->alias;
     } else
	  sym = NULL;
     return sym;
}

Symbol *
install(char *name, int flags)
{
     Symbol *sym;
     struct table_entry *tp, *ret;

     sym = xmalloc(sizeof(*sym));
     memset(sym, 0, sizeof(*sym));
     sym->type = SymUndefined;
     sym->name = name;
     sym->ord = -1;

     tp = xmalloc(sizeof(*tp));
     tp->sym = sym;

     if (((flags & INSTALL_CHECK_LOCAL) &&
	  canonical_filename && strcmp(filename, canonical_filename)) ||
	 (flags & INSTALL_UNIT_LOCAL)) {
	  sym->flag = symbol_local;
	  append_symbol(&static_symbol_list, sym);
     } else
	  sym->flag = symbol_none;

     if (! ((symbol_table
	     || (symbol_table = hash_initialize (0, 0, 
						 hash_symbol_hasher,
						 hash_symbol_compare, 0)))
	    && (ret = hash_insert (symbol_table, tp))))
	  xalloc_die ();

     if (ret != tp) {
	  if (flags & INSTALL_OVERWRITE) {
	       free(sym);
	       free(tp);
	       return ret->sym;
	  }
	  if (ret->sym->type != SymUndefined) 
	       sym->next = ret->sym;
	  ret->sym = sym;
	  free(tp);
     }
     sym->owner = ret;
     return sym;
}

void
ident_change_storage(Symbol *sp, enum storage storage)
{
     if (sp->storage == storage)
	  return;
     if (sp->storage == StaticStorage)
	  /* FIXME */;

     switch (storage) {
     case StaticStorage:
	  append_symbol(&static_symbol_list, sp);
	  break;
     case AutoStorage:
	  append_symbol(&auto_symbol_list, sp);
	  break;
     default:
	  symbol_unlink_from_list(sp);
	  break;
     }

     sp->storage = storage;
}

void
init_ident(Symbol *sp, enum storage storage)
{
     sp->type = SymIdentifier;
     sp->arity = -1;
     sp->storage = ExternStorage;
     sp->decl = NULL;
     sp->source = NULL;
     sp->def_line = -1;
     sp->ref_line = NULL;
     sp->caller = sp->callee = NULL;
     sp->level = -1;
     ident_change_storage(sp, storage);
}

Symbol *
install_ident(char *name, enum storage storage)
{
     Symbol *sp;

     sp = install(name, 
                  storage != AutoStorage ? 
                     INSTALL_CHECK_LOCAL : INSTALL_DEFAULT);
     init_ident(sp, storage);
     return sp;
}

static void
unlink_symbol(Symbol *sym)
{
     Symbol *s, *prev = NULL;
     struct table_entry *tp = sym->owner;
     for (s = tp->sym; s; ) {
	  Symbol *next = s->next;
	  if (s == sym) {
	       if (prev)
		    prev->next = next;
	       else
		    tp->sym = next;
	       break;
	  } else
	       prev = s;
	  s = next;
     }

     sym->owner = NULL;
}

static void
delete_symbol(Symbol *sym)
{
     unlink_symbol(sym);
     /* The symbol could have been referenced even if it is static
	in -i^s mode. See tests/static.at for details. */
     if (sym->ref_line == NULL && !(reverse_tree && sym->callee)) {
	  linked_list_destroy(&sym->ref_line);
	  linked_list_destroy(&sym->caller);
	  linked_list_destroy(&sym->callee);
	  free(sym);
     }
}

static void
static_free(void *data)
{
     Symbol *sym = data;
     struct table_entry *t = sym->owner;

     if (!t)
	  return;
     if (sym->flag == symbol_local) {
	  /* In xref mode, eligible unit-local symbols are retained in
	     unit_local_list for further processing.
	     Otherwise, they are deleted. */
	  if (print_option == PRINT_XREF && include_symbol(sym)) {
	       unlink_symbol(sym);
	       linked_list_append(&unit_local_list, sym);
	  } else {
	       delete_symbol(sym);
	  }
     } else {
	  unlink_symbol(sym);
	  if (symbol_is_function(sym))
	       linked_list_append(&static_func_list, sym);
     }
}

void
delete_statics()
{
     reset_static_caller();
     if (static_symbol_list) {
	  static_symbol_list->free_data = static_free;
	  linked_list_destroy(&static_symbol_list);
     }
}

int
delete_level_autos(void *data, void *call_data)
{
     int level = *(int*)call_data;
     Symbol *s = data;
     if (s->level == level) {
	  delete_symbol(s);
	  return 1;
     }
     return 0;
}

int
delete_level_statics(void *data, void *call_data)
{
     int level = *(int*)call_data;
     Symbol *s = data;
     if (s->level == level) {
	  unlink_symbol(s);
	  return 1;
     }
     return 0;
}

void
delete_autos(int level)
{
     linked_list_iterate(&auto_symbol_list, delete_level_autos, &level);
     linked_list_iterate(&static_symbol_list, delete_level_statics, &level);
}

static bool
collect_processor(void *data, void *proc_data)
{
     struct table_entry *t = data;
     struct collect_data *cd = proc_data;
     Symbol *s;
     for (s = t->sym; s; s = s->next) {
	  if (cd->sel(s)) {
	       if (cd->index == cd->count) {
		    cd->sym = x2nrealloc(cd->sym, &cd->count, sizeof(cd->sym[0]));
	       }
	       cd->sym[cd->index++] = s;
	  }
     }
     return true;
}

static int
collect_list_entry(void *item, void *proc_data)
{
     Symbol *s = item;
     struct collect_data *cd = proc_data;
     if (cd->sel(s)) {
	  if (cd->index == cd->count) {
	       cd->sym = x2nrealloc(cd->sym, &cd->count, sizeof(cd->sym[0]));
	  }
	  cd->sym[cd->index++] = s;
     }
     return 0;
}

size_t
collect_symbols(Symbol ***return_sym, int (*sel)(Symbol *p),
		size_t reserved_slots)
{
     struct collect_data cdata;

     cdata.sym = NULL;
     cdata.count = 0;
     cdata.index = 0;
     cdata.sel = sel;
     hash_do_for_each(symbol_table, collect_processor, &cdata);
     linked_list_iterate(&static_func_list, collect_list_entry, &cdata);
     linked_list_iterate(&unit_local_list, collect_list_entry, &cdata);

     cdata.sym = xrealloc(cdata.sym,
			  (cdata.index + reserved_slots) * sizeof(*cdata.sym));
     *return_sym = cdata.sym;
     return cdata.index;
}

size_t
collect_functions(Symbol ***return_sym)
{
     Symbol **symbols;
     size_t num, snum;
     struct linked_list_entry *p;

     /* Count static functions */
     snum = linked_list_size(static_func_list);

     /* Collect global functions */
     num = collect_symbols(&symbols, symbol_is_function, snum);

     /* Collect static functions */
     if (snum) 
	  for (p = linked_list_head(static_func_list); p; p = p->next)
	       symbols[num++] = p->data;
     *return_sym = symbols;
     return num;
}

int
delete_parms_itr(void *data, void *call_data)
{
     int level = *(int*)call_data;
     Symbol *s = data;
     struct table_entry *t = s->owner;

     if (!t)
	  return 1;
     if (s->type == SymIdentifier && s->storage == AutoStorage
	 && s->flag == symbol_parm && s->level > level) {
	  delete_symbol(s);
	  return 1;
     }
     return 0;
}

void
delete_parms(int level)
{
     linked_list_iterate(&auto_symbol_list, delete_parms_itr, &level);
}

void
move_parms(int level)
{
     struct linked_list_entry *p;

     for (p = linked_list_head(auto_symbol_list); p; p = p->next) {
	  Symbol *s = p->data;

	  if (s->type == SymIdentifier && s->storage == AutoStorage
	      && s->flag == symbol_parm) {
	       s->level = level;
	       s->flag = symbol_none;
	  }
     }
}

Symbol *
install_starter(char *name)
{
     Symbol *sp = install(name, 0);
     sp->flag = symbol_start;
     if (!data_in_list(sp, start_symbol_list))
	  linked_list_append(&start_symbol_list, sp);
     return sp;
}

void
set_default_starter(void)
{
     if (!linked_list_head(start_symbol_list))
	  install_starter("main");
}

void
clear_starters(void)
{
     linked_list_destroy(&start_symbol_list);
}

Symbol *
first_starter(void *itr)
{
     struct linked_list_entry *p = linked_list_head(start_symbol_list);
     while (p) {
	  Symbol *sym = p->data;
	  if (sym->type != SymUndefined) {
	       *(void**)itr = p->next;
	       return sym;
	  }
	  p = p->next;
     }
     *(void**)itr = NULL;
     return NULL;
}

Symbol *
next_starter(void *itr)
{
     struct linked_list_entry *p;

     if (!itr)
	  return NULL;
     p = *(void**)itr;
     while (p) {
	  Symbol *sym = p->data;
	  if (sym->type != SymUndefined) {
	       *(void**)itr = p->next;
	       return sym;
	  }
	  p = p->next;
     }
     *(void**)itr = NULL;
     return NULL;
}

Symbol *
install_target(char *name)
{
     Symbol *sp = install(name, 0);
     sp->flag = symbol_target;
     if (!data_in_list(sp, target_symbol_list))
	  linked_list_append(&target_symbol_list, sp);
     return sp;
}

static void
mark_callers(Symbol *sym)
{
     struct linked_list_entry *p;

     if (sym->active)
	  return;
     sym->active = 1;
     for (p = linked_list_head(sym->caller); p; p = p->next) {
	  mark_callers((Symbol*)p->data);
     }
     sym->visible = 1;
     sym->active = 0;
}

void
eliminate_non_targets(void)
{
     struct linked_list_entry *p;

     p = linked_list_head(target_symbol_list);

     if (!p)
	  return;

     for (; p; p = p->next) {
	  Symbol *sym = p->data;
	  if (sym->flag == symbol_target) {
	       mark_callers(sym);
	  }
     }
     output_visible = 1;
}

static void
set_usage_var (struct parseopt *po, char const *text, char **end)
{
  struct usage_var_def *p;
  int boolval = 1;
  size_t len = strcspn (text, ",=");
  char *endp;

  if (len > 3 && memcmp (text, "no-", 3) == 0)
    {
      text += 3;
      len -= 3;
      boolval = 0;
    }

  endp = (char *) text + len;

  for (p = usage_var; p->name; p++)
    {
      if (strlen (p->name) == len && memcmp (p->name, text, len) == 0)
	break;
    }

  if (p->name)
    {
      if (p->type == usage_var_bool)
	{
	  if (*endp == '=')
	    po->po_error (po, PO_MSG_ERR,
			  _("error in ARGP_HELP_FMT:"
			    " improper usage of [no-]%s"), p->name);
	  else
	    *p->valptr = boolval;
	}
      else if (*endp == '=')
	{
	  unsigned long val;

	  errno = 0;
	  val = strtoul (text + len + 1, &endp, 10);
	  if (errno || (*endp && *endp != ','))
	    po->po_error (po, PO_MSG_ERR,
			  _("error in ARGP_HELP_FMT:"
			    " bad value for %s (near %s)"),
			  p->name,
			  endp ? endp : "end");
	  else if (val > UINT_MAX)
	    po->po_error (po, PO_MSG_ERR,
			  _("error in ARGP_HELP_FMT:"
			    " %s value is out of range"), p->name);
	  else
	    *p->valptr = val;
	}
      else
	po->po_error (po, PO_MSG_ERR,
		      _("%s: ARGP_HELP_FMT parameter"
			" requires a value"), p->name);
    }
  else
    {
      po->po_error (po, PO_MSG_ERR,
		    _("%s: unknown ARGP_HELP_FMT parameter"), text);
      if (*endp == '=')
	endp += strcspn (endp, ",");
    }
  *end = endp;
}

static void
init_usage_vars (struct parseopt *po)
{
  char *fmt, *p;

  fmt = getenv ("ARGP_HELP_FMT");
  if (!fmt || !*fmt)
    return;

  while (1)
    {
      set_usage_var (po, fmt, &p);
      if (*p == 0)
	break;
      else if (*p == ',')
	p++;
      else
	{
	  po->po_error (po, PO_MSG_ERR,
			_("ARGP_HELP_FMT: missing delimiter near %s"), p);
	  break;
	}
      fmt = p;
    }
}

static inline void
print_arg (WORDWRAP_FILE wf, struct optdef *opt, int delim, int *argsused)
{
  if (opt->opt_argdoc)
    {
      *argsused = 1;
      if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
	wordwrap_printf (wf, "%c[%s]", delim, gettext (opt->opt_argdoc));
      else
	wordwrap_printf (wf, "%c%s", delim, gettext (opt->opt_argdoc));
    }
}

static inline struct optdef *
opt_unalias (struct optdef *opt)
{
  while (opt->opt_flags & OPTFLAG_ALIAS)
    opt--;
  return opt;
}

static void
parseopt_usage_std (struct parseopt *po, WORDWRAP_FILE wf)
{
  int i;
  struct optdef *opt, *orig;

  /* Print short options without arguments */
  for (i = 0; i < po->po_optcount; i++)
    {
      opt = po->po_optptr[po->po_optidx[i]];
      if (opt->opt_name[0] != 0 && opt->opt_name[1] == 0 &&
	  opt->opt_argdoc == NULL &&
	  !optdef_is_hidden (opt))
	break;
    }

  if (i < po->po_optcount)
    {
      wordwrap_puts (wf, "[-");
      wordwrap_puts (wf, opt->opt_name);
      while (++i < po->po_optcount)
	{
	  opt = po->po_optptr[po->po_optidx[i]];
	  if (opt->opt_name &&
	      opt->opt_name[0] != 0 && opt->opt_name[1] == 0 &&
	      opt->opt_argdoc == NULL &&
	      !optdef_is_hidden (opt))
	    wordwrap_puts (wf, opt->opt_name);
	}
      wordwrap_putc (wf, ']');
    }

  /* Print short options with arguments */
  for (i = 0; i < po->po_optcount; i++)
    {
      opt = po->po_optptr[po->po_optidx[i]];
      orig = opt_unalias (opt);
      if (opt->opt_name &&
	  opt->opt_name[0] != 0 && opt->opt_name[1] == 0 &&
	  orig->opt_argdoc != NULL &&
	  !optdef_is_hidden (orig))
	{
	  wordwrap_word_start (wf);
	  wordwrap_puts (wf, " [-");
	  wordwrap_puts (wf, opt->opt_name);
	  wordwrap_putc (wf, ' ');
	  wordwrap_puts (wf, gettext (orig->opt_argdoc));
	  wordwrap_putc (wf, ']');
	  wordwrap_word_end (wf);
	}
    }

  /* Print long options */
  for (i = 0; i < po->po_optcount; i++)
    {
      opt = po->po_optptr[po->po_optidx[i]];
      orig = opt_unalias (opt);
      if (opt->opt_name &&
	  opt->opt_name[0] != 0 && opt->opt_name[1] != 0 &&
	  !optdef_is_hidden (opt))
	{
	  wordwrap_word_start (wf);
	  wordwrap_write (wf, " [--", 4);
	  if (opt->opt_flags & OPTFLAG_BOOL)
	    wordwrap_printf (wf, "[%s]", po->po_negation);
	  wordwrap_puts (wf, opt->opt_name);
	  if (orig->opt_argdoc)
	    {
	      wordwrap_putc (wf, '=');
	      if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
		wordwrap_putc (wf, '[');
	      wordwrap_puts (wf, gettext (orig->opt_argdoc));
	      if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
		wordwrap_putc (wf, ']');
	    }
	  wordwrap_putc (wf, ']');
	  wordwrap_word_end (wf);
	}
    }
}

static void
parseopt_usage_sdash (struct parseopt *po, WORDWRAP_FILE wf)
{
  size_t i;

  for (i = 0; i < po->po_optcount; i++)
    {
      struct optdef *opt = po->po_optptr[po->po_optidx[i]];
      if (optdef_is_option (opt) && !optdef_is_hidden (opt))
	{
	  struct optdef *orig = opt_unalias (opt);

	  if (i > 0)
	    wordwrap_putc (wf, ' ');
	  wordwrap_word_start (wf);
	  wordwrap_write (wf, "[-", 2);
	  if (opt->opt_flags & OPTFLAG_BOOL)
	    wordwrap_printf (wf, "[%s]", po->po_negation);
	  wordwrap_puts (wf, opt->opt_name);
	  if (orig->opt_argdoc)
	    {
	      wordwrap_putc (wf, ' ');
	      if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
		wordwrap_putc (wf, '[');
	      wordwrap_puts (wf, gettext (orig->opt_argdoc));
	      if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
		wordwrap_putc (wf, ']');
	    }
	  wordwrap_putc (wf, ']');
	  wordwrap_word_end (wf);
	}
    }
}

void
parseopt_usage_fd (struct parseopt *po, int fd)
{
  WORDWRAP_FILE wf;

  init_usage_vars (po);
  wf = wordwrap_fdopen (fd);
  wordwrap_set_right_margin (wf, FMT(rmargin));
  wordwrap_printf (wf, "%s %s ", _("Usage:"), po->po_program_name);
  wordwrap_next_left_margin (wf, FMT(usage_indent));

  if (po->po_flags & PARSEOPT_SINGLE_DASH)
    parseopt_usage_sdash (po, wf);
  else
    parseopt_usage_std (po, wf);

  if (po->po_argdoc)
    wordwrap_printf (wf, " %s\n", gettext (po->po_argdoc));

  if (po->po_program_args)
    {
      size_t i;

      for (i = 0; po->po_program_args[i]; i++)
	{
	  wordwrap_set_left_margin (wf, 2);
	  wordwrap_next_left_margin (wf, FMT(usage_indent));
	  wordwrap_printf (wf, _("or: %s [OPTIONS...] %s\n"),
			   po->po_program_name,
			   gettext (po->po_program_args[i]));
	}
    }

  wordwrap_close (wf);
}

static inline size_t
min (size_t a, size_t b)
{
  return a < b ? a : b;
}

static void
merge (struct optdef const *optv, int *source, int *work,
       size_t left, size_t right, size_t end,
       OPTCMP cmp)
{
  size_t i = left;
  size_t j = right;
  size_t k;

  for (k = left; k < end; k++)
    {
      if (i < right
	  && (j >= end || cmp (optv, source, i, j) <= 0))
	work[k] = source[i++];
      else
	work[k] = source[j++];
    }
}

static int
optsort (struct optsort *ops, int n)
{
  int *tmp, *a, *b;
  size_t width;

  tmp = calloc (n, sizeof (tmp[0]));
  if (!tmp)
    return -1;

  a = ops->idx + ops->opti;
  b = tmp;
  for (width = 1; width < n; width <<= 1)
    {
      size_t i;
      int *t;

      for (i = 0; i < n; i += 2 * width)
	{
	  merge (ops->optv, a, b,
		 i, min (i + width, n), min (i + 2 * width, n),
		 ops->cmp);
	}
      t = a;
      a = b;
      b = t;
    }
  if (b != tmp)
    memcpy (b, tmp, n * sizeof (ops->idx[0]));
  free (tmp);
  return 0;
}

static void
print_option_std (WORDWRAP_FILE wf, struct help_context *ctx,
		  struct optdef *cur_opt,
		  size_t i, size_t next)
{
  struct optdef *opt;
  int delim = 0;
  int w;

  /* Format short options. */
  w = 0;
  for (; i < next; i++)
    {
      opt = &ctx->opts[ctx->idx[i]];
      if (optdef_is_hidden (opt))
	continue;
      if (opt->opt_name[1])
	break;
      if (w)
	wordwrap_write (wf, ", ", 2);
      wordwrap_putc (wf, '-');
      wordwrap_puts (wf, opt->opt_name);
      delim = ' ';
      if (FMT(dup_args))
	print_arg (wf, cur_opt, delim, &ctx->argsused);
      w = 1;
    }

  /* Format long options. */
  for (; i < next; i++)
    {
      opt = &ctx->opts[ctx->idx[i]];
      if (!optdef_is_hidden (opt))
	{
	  if (w)
	    wordwrap_write (wf, ", ", 2);
	  wordwrap_set_left_margin (wf, FMT(long_opt_col));
	  w = 0;
	  break;
	}
    }

  for (; i < next; i++)
    {
      opt = &ctx->opts[ctx->idx[i]];
      if (!optdef_is_hidden (opt))
	{
	  if (w)
	    wordwrap_write (wf, ", ", 2);
	  wordwrap_puts (wf, "--");
	  if (opt->opt_flags & OPTFLAG_BOOL)
	    wordwrap_printf (wf, "[%s]", ctx->po->po_negation);
	  wordwrap_puts (wf, opt->opt_name);
	  delim = '=';
	  if (FMT(dup_args))
	    print_arg (wf, cur_opt, delim, &ctx->argsused);
	  w = 1;
	}
    }
  if (delim && !FMT(dup_args))
    print_arg (wf, cur_opt, delim, &ctx->argsused);
}

static void
print_option_sdash (WORDWRAP_FILE wf, struct help_context *ctx,
		    struct optdef *cur_opt,
		    size_t i, size_t next)
{
  int w = 0;
  int delim = 0;
  for (; i < next; i++)
    {
      struct optdef *opt = &ctx->opts[ctx->idx[i]];
      if (!optdef_is_hidden (opt))
	{
	  if (w)
	    wordwrap_write (wf, ", ", 2);
	  wordwrap_putc (wf, '-');
	  if (opt->opt_flags & OPTFLAG_BOOL)
	    wordwrap_printf (wf, "[%s]", ctx->po->po_negation);
	  wordwrap_puts (wf, opt->opt_name);
	  delim = '=';
	  if (FMT(dup_args))
	    print_arg (wf, cur_opt, delim, &ctx->argsused);
	  w = 1;
	}
    }
  if (delim && !FMT(dup_args))
    print_arg (wf, cur_opt, delim, &ctx->argsused);
}

static int
print_option (WORDWRAP_FILE wf, struct help_context *ctx, int i)
{
  struct optdef *opt = &ctx->opts[ctx->idx[i]], *cur_opt = NULL;
  int next;
  struct optdef *head;

  if (optdef_is_hidden (opt))
    return i + 1;

  /* Mark the doc entry as list if its opt_name is set. */
  if ((opt->opt_flags & OPTFLAG_DOC) && opt->opt_name)
    opt->opt_flags |= OPTFLAG_LIST;
  /* Insert a newline between two contiguous plain doc entries,
     and between two entries of different doc type. */
  if (ctx->prev_doc != -1 &&
      ((ctx->prev_doc != (opt->opt_flags & OPTDOC_MASK)) ||
       (ctx->prev_doc == OPTFLAG_DOC && opt->opt_flags == OPTFLAG_DOC)))
    wordwrap_putc (wf, '\n');
  /* Save doc flags for use in the next call. */
  ctx->prev_doc = opt->opt_flags & OPTDOC_MASK;

  /* Handle a doc entry */
  if (opt->opt_flags & OPTFLAG_DOC)
    {
      wordwrap_set_right_margin (wf, FMT(rmargin));
      if (opt->opt_name)
	{
	  wordwrap_set_left_margin (wf,
				    (opt->opt_flags & OPTFLAG_SUBLIST)
				    ? FMT(sublist_col) : FMT(short_opt_col));
	  wordwrap_puts (wf, opt->opt_name);
	  wordwrap_set_left_margin (wf,
				    (opt->opt_flags & OPTFLAG_SUBLIST)
				    ? FMT(sublist_doc_col) : FMT(opt_doc_col));
	}
      else
	{
	  wordwrap_set_left_margin (wf,
				    (opt->opt_flags & OPTFLAG_SUBLIST)
				    ? FMT(sublist_col) : FMT(doc_opt_col));
	}
      if (opt->opt_doc)
	{
	  wordwrap_puts (wf, gettext (opt->opt_doc));
	  if (ctx->prev_doc)
	    wordwrap_putc (wf, '\n');
	}
      return i + 1;
    }

  /* A regular option. */

  /* Find next index and canonical option. */
  head = opt->opt_head;
  if (!(opt->opt_flags & OPTFLAG_ALIAS))
    cur_opt = opt;
  for (next = i + 1; next < ctx->nidx &&
	 optdef_is_option (opt = &ctx->opts[ctx->idx[next]]) &&
	 opt->opt_head == head; next++)
    {
      if (!(opt->opt_flags & OPTFLAG_ALIAS))
	cur_opt = opt;
    }

  assert(cur_opt != NULL);

  wordwrap_set_left_margin (wf, FMT(short_opt_col));

  if (ctx->po->po_flags & PARSEOPT_SINGLE_DASH)
    print_option_sdash (wf, ctx, cur_opt, i, next);
  else
    print_option_std (wf, ctx, cur_opt, i, next);


  wordwrap_set_left_margin (wf, FMT(opt_doc_col));
  if (cur_opt->opt_doc && cur_opt->opt_doc[0])
    wordwrap_puts (wf, gettext (cur_opt->opt_doc));
  wordwrap_putc (wf, '\n');

  return next;
}

static int
optcmp (struct optdef const *optv, int *idx, int i, int j)
{
  struct optdef const *ap = &optv[idx[i]];
  struct optdef const *bp = &optv[idx[j]];

  if (ap->opt_head == bp->opt_head)
    {
      if (optdef_is_option (ap))
	{
	  if (optdef_is_option (bp))
	    {
	      if (ap->opt_name[1])
		{
		  if (!bp->opt_name[1])
		    return 1;
		}
	      else if (bp->opt_name[1])
		return -1;
	    }
	  else
	    return -1;
	}
      else if (optdef_is_option (bp))
	return 1;
    }
  else
    {
      ap = ap->opt_head;
      bp = bp->opt_head;
    }
  return strcmp (ap->opt_name ? ap->opt_name : "",
		 bp->opt_name ? bp->opt_name : "");
}

static void
sortnames (struct optsort *ops, int i, int j)
{
  i += ops->opti;
  j += ops->opti;
  while (j > i)
    {
      if (optcmp (ops->optv, ops->idx, i, j) <= 0)
	break;
      else
	{
	  int t = ops->idx[j];
	  ops->idx[j] = ops->idx[i];
	  ops->idx[i] = t;
	}
      j--;
    }
}

static inline void
sethead (struct optsort *ops, int i, int n)
{
  struct optdef *head = &ops->optv[ops->idx[ops->opti + i]];
  for (;i < n; i++)
    ops->optv[ops->idx[ops->opti + i]].opt_head = head;
}

static void
sort_group (struct optsort *ops)
{
  size_t i, j;
  struct optdef *opt;

  /* Skip documentation entries */
  while (ops->opti < ops->optc && optdef_is_doc_string (&ops->optv[ops->opti]))
    {
      ops->idx[ops->opti] = ops->opti;
      ops->opti++;
    }

  /* Copy optdefs, sorting each option cluster by option name.  Short
     option variants sort first.  Since clusters normally are very small,
     bubble sort is used. */
  i = j = 0;
  while (ops->opti + i < ops->optc &&
	 (optdef_is_option (opt = &ops->optv[ops->opti + i])
	  || optdef_is_option_doc (opt)))
    {
      ops->idx[ops->opti + i] = ops->opti + i;
      if (optdef_is_option (opt) && !(opt->opt_flags & OPTFLAG_ALIAS))
	{
	  if (i > j)
	    sethead (ops, j, i);
	  /* Start next cluster. */
	  j = i;
	}
      opt->opt_head = NULL;
      sortnames (ops, j, i);
      i++;
    }
  if (i > j)
    sethead (ops, j, i);

  /* Sort collected options */
  optsort (ops, i);

  ops->opti += i;
}

static void
sort_options (struct help_context *ctx)
{
  struct optsort opts;

  opts.cmp = optcmp;
  opts.optv = ctx->opts;
  for (opts.optc = 0; !optdef_is_end (&opts.optv[opts.optc]); opts.optc++);

  opts.idx = calloc (opts.optc, sizeof (opts.idx[0]));
  if (opts.idx == NULL)
    abort ();

  ctx->idx = opts.idx;
  ctx->nidx = opts.optc;

  for (opts.opti = 0; opts.opti < opts.optc;)
    sort_group (&opts);
}

static void
print_option_group (WORDWRAP_FILE wf, struct help_context *ctx)
{
  size_t i;

  sort_options (ctx);

  for (i = 0; i < ctx->nidx;)
    i = print_option (wf, ctx, i);

  free (ctx->idx);
}

void
parseopt_help_fd (struct parseopt *po, int fd)
{
  WORDWRAP_FILE wf;
  struct help_context ctx = {
    .po = po,
    .argsused = 0,
    .prev_doc = -1
  };
  size_t i;

  init_usage_vars (po);

  wf = wordwrap_fdopen (fd);

  wordwrap_printf (wf, _("usage: %s"), po->po_program_name);
  if (po->po_argdoc) {
	  wordwrap_putc (wf, ' ');
	  wordwrap_puts (wf, gettext (po->po_argdoc));
  } else if (po->po_optcount) {
	  wordwrap_putc (wf, ' ');
	  wordwrap_puts (wf, gettext ("[OPTIONS...]"));
  }

  wordwrap_putc (wf, '\n');

  if (po->po_program_args)
    {
      for (i = 0; po->po_program_args[i]; i++)
	{
	  wordwrap_set_left_margin (wf, 3);
	  wordwrap_next_left_margin (wf, FMT(usage_indent));
	  wordwrap_printf (wf, _("or: %s %s\n"), po->po_program_name,
			   gettext (po->po_program_args[i]));
	}
      wordwrap_set_left_margin (wf, 0);
    }

  wordwrap_set_right_margin (wf, FMT(rmargin));
  if (po->po_descr)
    wordwrap_puts (wf, gettext (po->po_descr));
  if (po->po_prog_doc_hook)
    {
      if (po->po_descr)
	wordwrap_para (wf);
      po->po_prog_doc_hook (wf, po);
    }
  wordwrap_para (wf);

  for (i = 0; po->po_optgrp[i]; i++)
    {
      ctx.opts = po->po_optgrp[i];
      print_option_group (wf, &ctx);
    }

  wordwrap_para (wf);
  if (ctx.argsused && !FMT(dup_args) && FMT(dup_args_note))
    {
      wordwrap_set_left_margin (wf, 0);
      wordwrap_set_right_margin (wf, FMT(rmargin));
      wordwrap_puts (wf,
	gettext (dup_args_note_text[!!(po->po_flags & PARSEOPT_SINGLE_DASH)]));
      wordwrap_para (wf);
    }

  if (po->po_help_hook)
    {
      wordwrap_set_left_margin (wf, 0);
      po->po_help_hook (wf, po);
      wordwrap_para (wf);
    }

  wordwrap_set_left_margin (wf, 0);
  wordwrap_set_right_margin (wf, FMT(rmargin));

  if (po->po_bugreport_address)
    wordwrap_printf (wf,
		     _("Report bugs and suggestions to <%s>\n"),
		     po->po_bugreport_address);
  if (po->po_package_name && po->po_package_url)
    wordwrap_printf (wf,
		     _("%s home page: <%s>\n"), po->po_package_name,
		     po->po_package_url);
  if (po->po_general_help)
    wordwrap_puts (wf, gettext (po->po_general_help));

  wordwrap_close (wf);
}

void
parseopt_version_fd (struct parseopt *po, int fd)
{
  WORDWRAP_FILE wf;

  if (!po->po_version_hook)
    return;

  init_usage_vars (po);
  wf = wordwrap_fdopen (fd);
  po->po_version_hook (wf, po);
  wordwrap_close (wf);
}

static int
get_signed_int (char *arg, intmax_t min, intmax_t max, intmax_t *ret_val)
{
  intmax_t n;
  char *p;

  errno = 0;
  n = strtoimax (arg, &p, 10);
  if (errno || *p)
    return -1;
  if (n < min || n > max)
    return -1;
  *ret_val = n;
  return 0;
}

static int
get_unsigned_int (char *arg, uintmax_t max, uintmax_t *ret_val)
{
  uintmax_t n;
  char *p;

  errno = 0;
  n = strtoumax (arg, &p, 10);
  if (errno || *p)
    return -1;
  if (n > max)
    return -1;
  *ret_val = n;
  return 0;
}

int
optset_incr (struct parseopt *po, struct optdef *opt, char *arg)
{
  assert (opt->opt_ptr != NULL);
  assert (arg == NULL);
  (*(int*) opt->opt_ptr) ++;
  return 0;
}

int
optset_string_copy (struct parseopt *po, struct optdef *opt, char *arg)
{
  assert (opt->opt_ptr != NULL);
  *(char **) opt->opt_ptr = arg;
  return 0;
}

int
optset_string (struct parseopt *po, struct optdef *opt, char *arg)
{
  char *p;
  assert (opt->opt_ptr != NULL);
  if (arg == NULL)
    return -1;
  if ((p = strdup (arg)) == NULL)
    {
      po->po_error (po, PO_MSG_ERR, _("memory allocation error"));
      return 0;
    }
  *(char **) opt->opt_ptr = p;
  return 0;
}

int
optset_string_alloc (struct parseopt *po, struct optdef *opt, char *arg)
{
  char *p;
  assert (opt->opt_ptr != NULL);
  if (arg == NULL)
    return -1;
  if ((p = strdup (arg)) == NULL)
    {
      po->po_error (po, PO_MSG_ERR, _("memory allocation error"));
      return 0;
    }
  free (*(char **) opt->opt_ptr);
  *(char **) opt->opt_ptr = p;
  return 0;
}

int
optset_true (struct parseopt *po, struct optdef *opt, char *arg)
{
  *(int *) opt->opt_ptr = 1;
  return 0;
}

int
optset_false (struct parseopt *po, struct optdef *opt, char *arg)
{
  *(int *) opt->opt_ptr = 0;
  return 0;
}

int
optset_bool (struct parseopt *po, struct optdef *opt, char *arg)
{
  *(int *) opt->opt_ptr = arg[0] == '1';
  return 0;
}

char const *
option_dash (struct parseopt *po, struct optdef *opt)
{
  return dash_str[((po->po_flags & PARSEOPT_SINGLE_DASH) ||
		   strlen (opt->opt_name) == 1) ? 1 : 2];
}

static struct optdef *
option_find_short (struct parseopt *po, struct optdef **orig_opt,
		   char **argptr, int *exparg)
{
  int i;

  for (i = 0; i < po->po_optcount; i++)
    {
      struct optdef *opt = po->po_optptr[po->po_optidx[i]];
      size_t namelen = strlen (opt->opt_name);

      if (namelen == 1 && opt->opt_name[0] == po->po_optname[0])
	{
	  *orig_opt = opt;
	  while (opt->opt_flags & OPTFLAG_ALIAS)
	    opt--;
	  if (opt->opt_argdoc && po->po_optname[1])
	    {
	      *exparg = 1;
	      *argptr = (char *) po->po_optname + 1;
	      po->po_opt_buf[0] = po->po_optname[0];
	      po->po_opt_buf[1] = 0;
	      po->po_optname = po->po_opt_buf;
	    }
	  else
	    {
	      *exparg = 0;
	      if (opt->opt_flags & OPTFLAG_BOOL)
		*argptr = "1";
	      else
		*argptr = NULL;
	    }
	  return opt;
	}
    }

  po->po_error (po, PO_MSG_ERR,
		_("unrecognized option '-%c'"), po->po_optname[0]);

  return NULL;
}

static enum neg_match
negmatch (struct parseopt *po, struct optdef const *opt,
	  char const *optstr, size_t optlen)
{
  if (opt->opt_flags & OPTFLAG_BOOL)
    {
      size_t neglen = strlen (po->po_negation);
      size_t len = strlen (opt->opt_name);
      if (optlen <= neglen + len
	  && memcmp (optstr, po->po_negation, neglen) == 0
	  && memcmp (optstr + neglen, opt->opt_name,
		     optlen - neglen) == 0)
	{
	  return (optlen == neglen + len) ? neg_match_exact : neg_match_inexact;        }
    }
  return neg_nomatch;
}

static struct optdef *
option_find_long (struct parseopt *po, struct optdef **orig_opt, char **argptr,
		  int *exparg)
{
  size_t optlen = strcspn (po->po_optname, "=");
  int i;
  int found = 0;
  struct optdef *found_opt = NULL;
  int negated = 0;

  for (i = 0; i < po->po_optcount; i++)
    {
      struct optdef *opt = po->po_optptr[po->po_optidx[i]];
      size_t namelen = strlen (opt->opt_name);
      enum neg_match neg = neg_not_tried;

      /* Ignore single-letter options when used with -- */
      if (namelen == 1 && !(po->po_flags & PARSEOPT_SINGLE_DASH))
	continue;

      if ((optlen <= namelen &&
	   memcmp (opt->opt_name, po->po_optname, optlen) == 0)
	  || (neg = negmatch (po, opt, po->po_optname, optlen)) != neg_nomatch)
	{
	  switch (found)
	    {
	    case 0:
	      found_opt = opt;
	      found++;
	      negated = neg > neg_nomatch;
	      if (optlen == namelen || neg == neg_match_exact)
		{
		  /* Exact match */
		  goto end;
		}
	      break;

	    case 1:
	      found++;
	      po->po_error (po, PO_MSG_ERR,
			    _("option '%s%*.*s' is ambiguous; possibilities:"),
			    dash_str[po->po_dash_count],
			    optlen, optlen, po->po_optname);
	      po->po_error (po, PO_MSG_INFO, "%s%s%s",
			    dash_str[po->po_dash_count],
			    negated ? po->po_negation : "",
			    found_opt->opt_name);
	      if (!negated &&
		  negmatch (po, found_opt, po->po_optname, optlen) != neg_nomatch)
		po->po_error (po, PO_MSG_INFO, "%s%s%s",
			      dash_str[po->po_dash_count],
			      po->po_negation,
			      found_opt->opt_name);
	      /* fall through */
	    case 2:
	      po->po_error (po, PO_MSG_INFO, "%s%s%s",
		       dash_str[po->po_dash_count],
		       neg > neg_nomatch ? po->po_negation : "",
		       opt->opt_name);
	      if (neg == neg_not_tried &&
		  negmatch (po, opt, po->po_optname, optlen) != neg_nomatch)
		po->po_error (po, PO_MSG_INFO, "%s%s%s",
			 dash_str[po->po_dash_count],
			 po->po_negation,
			 found_opt->opt_name);
	    }
	}
    }
end:
  switch (found)
    {
    case 0:
      po->po_error (po, PO_MSG_ERR, _("unrecognized option '%s%*.*s'"),
		    dash_str[po->po_dash_count], optlen, optlen,
		    po->po_optname);
      break;

    case 1:
      *orig_opt = found_opt;
      while (found_opt->opt_flags & OPTFLAG_ALIAS)
	found_opt--;
      if (po->po_optname[optlen] == '=')
	{
	  *argptr = (char *) po->po_optname + optlen + 1;
	  *exparg = 1;
	}
      else
	{
	  *exparg = 0;
	  if (found_opt->opt_flags & OPTFLAG_BOOL)
	    *argptr = negated ? "0" : "1";
	  else
	    *argptr = NULL;
	}
      return found_opt;

    case 2:
      break;
    }
  return NULL;
}

static void
permute (struct parseopt *po)
{
  if (!(po->po_flags & PARSEOPT_IN_ORDER) && po->po_arg_count)
    {
      /* Array to save arguments in */
      char *save[2];
      /* Number of arguments processed (at most two) */
      int n = po->po_argi - (po->po_arg_start + po->po_arg_count);
      assert (n <= 2);

      /* Store the processed elements away */
      save[0] = po->po_argv[po->po_arg_start + po->po_arg_count];
      if (n == 2)
	save[1] = po->po_argv[po->po_arg_start + po->po_arg_count + 1];

      /* Shift the array */
      memmove (po->po_argv + po->po_arg_start + n,
	       po->po_argv + po->po_arg_start,
	       po->po_arg_count * sizeof (po->po_argv[0]));

      /* Place saved elements in the vacating slots */
      po->po_argv[po->po_arg_start] = save[0];
      if (n == 2)
	po->po_argv[po->po_arg_start + 1] = save[1];

      /* Fix up start index */
      po->po_arg_start += n;
      po->po_permuted = 1;
    }
}

char const *
parseopt_lookahead (struct parseopt *po)
{
  if (!((po->po_flags & PARSEOPT_SINGLE_DASH)) &&
      po->po_dash_count == 1 && po->po_optname && po->po_optname[1])
    return po->po_optname;
  else
    return po->po_argv[po->po_argi];
}

void
parseopt_skip (struct parseopt *po)
{
  if (po->po_argi == po->po_argc || po->po_eopt)
    return;
  po->po_argi++;
}

static int
parseopt_next_internal (struct parseopt *po, char **ret_arg)
{
  char *opt_arg;

  if (!((po->po_flags & PARSEOPT_SINGLE_DASH)) &&
      po->po_dash_count == 1 && po->po_optname && po->po_optname[1])
    po->po_optname++;
  else
    {
      permute (po);

      for (;;)
	{
	  char *arg;

	  po->po_dash_count = 0;

	  if (po->po_argi == po->po_argc || po->po_eopt)
	    break;

	  arg = po->po_argv[po->po_argi++];

	  if (*arg == '-')
	    {
	      arg++;
	      po->po_dash_count++;
	      if (*arg == '-')
		{
		  arg++;
		  po->po_dash_count++;
		  if (*arg == 0)
		    {
		      po->po_dash_count = 0;
		      permute (po);
		      po->po_eopt = 1;
		      break;
		    }
		  if (po->po_flags & PARSEOPT_SINGLE_DASH)
		    {
		      arg--;
		      po->po_dash_count--;
		    }
		}
	      po->po_optname = arg;
	      break;
	    }
	  else if (po->po_flags & PARSEOPT_IN_ORDER)
	    {
	      po->po_argi--;
	      break;
	    }
	  else
	    {
	      if (!po->po_permuted && po->po_arg_count == 0)
		po->po_arg_start = po->po_argi - 1;
	      po->po_arg_count++;
	    }
	}
    }

  if (po->po_dash_count)
    {
      struct optdef *opt, *orig_opt;
      int has_arg;
      opt = ((po->po_dash_count == 2 || po->po_flags & PARSEOPT_SINGLE_DASH)
	     ? option_find_long : option_find_short) (po, &orig_opt, &opt_arg,
						      &has_arg);
      if (!opt)
	{
	  if (po->po_flags & PARSEOPT_NO_ERREXIT)
	    return OPT_ERR;
	  exit (po->po_ex_usage);
	}
      if (opt->opt_argdoc)
	{
	  if (opt_arg)
	    /* nothing */;
	  else if (opt->opt_flags & OPTFLAG_ARG_OPTIONAL)
	    opt_arg = NULL;
	  else if (po->po_argi == po->po_argc)
	    {
	      po->po_error (po, PO_MSG_ERR,
			    _("option '%s%s' requires argument"),
			    dash_str[po->po_dash_count], orig_opt->opt_name);
	      if (po->po_flags & PARSEOPT_NO_ERREXIT)
		return OPT_ERR;
	      exit (po->po_ex_usage);
	    }
	  else
	    opt_arg = po->po_argv[po->po_argi++];
	  if (!opt->opt_set)
	    *ret_arg = opt_arg;
	}
      else if (has_arg)
	{
	  po->po_error (po, PO_MSG_ERR,
			_("option '%s%s' does not take argument"),
			dash_str[po->po_dash_count], orig_opt->opt_name);
	  if (po->po_flags & PARSEOPT_NO_ERREXIT)
	    return OPT_ERR;
	  exit (po->po_ex_usage);
	}

      if ((!!(po->po_flags & PARSEOPT_EARLY)) ^
	  (!!(opt->opt_flags & OPTFLAG_EARLY)))
	return OPT_NEXT;

      opt->opt_flags |= OPTFLAG_IS_SET;

      if (opt->opt_set)
	{
	  if (opt->opt_set (po, opt, opt_arg))
	    {
	      po->po_error (po, PO_MSG_ERR,
			    _("bad value for option '%s%s'"),
			    dash_str[po->po_dash_count], orig_opt->opt_name);
	      if (po->po_flags & PARSEOPT_NO_ERREXIT)
		return OPT_ERR;
	      exit (po->po_ex_usage);
	    }
	  return OPT_NEXT;
	}
      return opt->opt_code;
    }

  if (!po->po_permuted)
    po->po_arg_start = po->po_argi - po->po_arg_count;

  opt_arg = po->po_argv[po->po_arg_start];

  if (opt_arg && (po->po_flags & PARSEOPT_NONOPT_ARG))
    {
      po->po_argi++;
      if (po->po_flags & PARSEOPT_EARLY)
	return OPT_NEXT;
      if (po->po_arg_set)
	{
	  if (po->po_arg_set->opt_set (po, po->po_arg_set, opt_arg))
	    {
	      po->po_error (po, PO_MSG_ERR,
			    _("invalid argument '%s'"), opt_arg);
	      if (po->po_flags & PARSEOPT_NO_ERREXIT)
		return OPT_ERR;
	      exit (po->po_ex_usage);
	    }
	  return OPT_NEXT;
	}
      else
	{
	  *ret_arg = opt_arg;
	  return OPT_ARG;
	}
    }

  *ret_arg = opt_arg;

  return OPT_END;
}

int
parseopt_next (struct parseopt *po, char **ret_arg)
{
  int rc;
  do
    rc = parseopt_next_internal (po, ret_arg);
  while (rc == OPT_NEXT);
  return rc;
}

void
parseopt_argv (struct parseopt *po, int *argc, char ***argv)
{
  *argc = po->po_argc - po->po_arg_start;
  *argv = po->po_argv + po->po_arg_start;
}

void
parseopt_error (struct parseopt *po, int pri, char const *fmt, ...)
{
  va_list ap;

  if (po->po_flags & PARSEOPT_IGNORE_ERRORS)
    return;

  if (po->po_program_name && pri == PO_MSG_ERR)
    fprintf (stderr, "%s: ", po->po_program_name);
  va_start (ap, fmt);
  vfprintf (stderr, fmt, ap);
  va_end (ap);
  fputc ('\n', stderr);
}

static int
find_short_name (struct optdef *opt)
{
  do
    {
      if (optdef_is_short_option (opt))
	return opt->opt_name[0];
    }
  while (!optdef_is_end (++opt) && (opt->opt_flags & OPTFLAG_ALIAS));
  return 0;
}

static int
optidx_slot (struct parseopt *po, int n, struct optdef *opt)
{
  int i, j, m;

  if (n == 0)
    return 0;
  i = 0;
  j = n;
  while (i < j)
    {
      m = i + ((j - i) / 2);
      if (strcmp (po->po_optptr[po->po_optidx[m]]->opt_name,
		  opt->opt_name) <= 0)
	i = m + 1;
      else
	j = m;
    }
  return i;
}

static size_t
collect_optdef (struct parseopt *po, struct optdef *opt, size_t n)
{
  size_t i, j;

  for (i = 0; !optdef_is_end (&opt[i]); i++)
    {
      if (optdef_is_option (&opt[i]))
	{
	  po->po_optptr[n] = &opt[i];
	  j = optidx_slot (po, n, &opt[i]);
	  if (j < n)
	    memmove (po->po_optidx + j + 1, po->po_optidx + j,
		     (n - j) * sizeof (po->po_optidx[0]));
	  po->po_optidx[j] = n;
	  n++;
	}
    }
  return n;
}

static void
prepare_optdef (struct parseopt *po, struct optdef *opt, int *scan_flags)
{
  int i;

  /* Ensure sane start of options. */
  opt[0].opt_flags &= ~(OPTFLAG_ALIAS|OPTFLAG_SUBLIST);

  /* Count actual options.  Check each of them for consistency and set
     opt_code field where needed. */
  for (i = 0; !optdef_is_end (&opt[i]); i++)
    {
      if (optdef_is_option (&opt[i]))
	{
	  po->po_optcount++;

	  if (opt[i].opt_code == OPT_ARG)
	    {
	      opt[i].opt_flags = OPTFLAG_HIDDEN;
	      po->po_flags |= PARSEOPT_NONOPT_ARG;
	      if (opt[i].opt_set)
		po->po_arg_set = &opt[i];
	      continue;
	    }

	  if (po->po_version_hook && strcmp (opt[i].opt_name, "V") == 0)
	    {
	      *scan_flags |= SCANF_V;
	    }

	  if (!(opt[i].opt_flags & OPTFLAG_ALIAS))
	    {
	      opt[i].opt_flags &= ~OPTFLAG_IS_SET;
	      if (opt[i].opt_code == 0)
		opt[i].opt_code = find_short_name (&opt[i]);
	      if (opt[i].opt_flags & OPTFLAG_BOOL)
		{
		  opt[i].opt_flags &= ~OPTFLAG_ARG_OPTIONAL;
		  opt[i].opt_argdoc = NULL;
		  if (opt[i].opt_ptr)
		    opt[i].opt_set = optset_bool;
		  if (!po->po_negation)
		    po->po_negation = parseopt_negation_prefix;
		}
	      if (opt[i].opt_flags & OPTFLAG_EARLY)
		   po->po_flags |= PARSEOPT_EARLY;
	    }
	}
    }
}

static int
set_help (struct parseopt *po, struct optdef *opt, char *arg)
{
  parseopt_help (po);
  exit (0);
}

static int
set_usage (struct parseopt *po, struct optdef *opt, char *arg)
{
  parseopt_usage (po);
  exit (0);
}

static int
set_version (struct parseopt *po, struct optdef *opt, char *arg)
{
  parseopt_version (po);
  exit (0);
}

static inline struct optdef *
_parseopt_optgroup (struct parseopt *po, int i)
{
  if (po->po_optdef)
    return po->po_optdef[i];
  return NULL;
}

int
parseopt_init0 (struct parseopt *po)
{
  size_t i, j, n;
  struct optdef *opt;
  int sf = (po->po_flags & PARSEOPT_SINGLE_DASH) ? SCANF_V : 0;

  po->po_flags &= PARSEOPT_USER_MASK;
  if (po->po_ex_usage == 0)
    po->po_ex_usage = EX_USAGE;
  if (!po->po_error)
    po->po_error = parseopt_error;

  /* Prepare options. */
  for (n = 0; _parseopt_optgroup (po, n) != NULL; n++)
    ;
  if (!(po->po_flags & PARSEOPT_NO_STDOPT))
    n++;
  if (po->po_version_hook)
    n++;

  po->po_optgrp = calloc (n + 1, sizeof (po->po_optgrp[0]));
  if (po->po_optgrp == NULL)
    return -1;

  po->po_optcount = 0;
  for (i = 0; (opt = _parseopt_optgroup (po, i)) != NULL; i++)
    prepare_optdef (po, po->po_optgrp[i] = opt, &sf);
  if (!(po->po_flags & PARSEOPT_NO_STDOPT))
    prepare_optdef (po, po->po_optgrp[i++] = stdopt, &sf);
  if (po->po_version_hook)
    prepare_optdef (po, po->po_optgrp[i++] = (sf & SCANF_V) ? veropt : veropt2,
		    &sf);

  po->po_optptr = calloc (po->po_optcount, sizeof (po->po_optptr[0]));
  if (po->po_optptr == NULL)
    {
      free (po->po_optgrp);
      return -1;
    }
  po->po_optidx = calloc (po->po_optcount, sizeof (po->po_optidx[0]));
  if (po->po_optidx == NULL)
    {
      free (po->po_optgrp);
      free (po->po_optptr);
      return -1;
    }

  /* Collect and index options. */
  j = 0;
  for (i = 0; i < n; i++)
    j = collect_optdef (po, po->po_optgrp[i], j);

  assert (j == po->po_optcount);

  if (po->po_flags & PARSEOPT_NONOPT_ARG)
    po->po_flags |= PARSEOPT_IN_ORDER;

  po->po_flags |= PARSEOPT_INITIALIZED;

  return 0;
}

int
parseopt_init (struct parseopt *po, int argc, char **argv)
{
  if (!(po->po_flags & PARSEOPT_INITIALIZED))
    if (parseopt_init0 (po))
      return -1;

  po->po_argc = argc;
  po->po_argv = argv;
  po->po_argi = 0;

  if (!(po->po_flags & PARSEOPT_ARGV0))
    {
      po->po_argi++;
      if (!po->po_program_name)
	{
	  char *p = strrchr (po->po_argv[0], '/');
	  if (p)
	    p++;
	  else
	    p = (char*) po->po_argv[0];
	  if (strlen (p) > 3 && memcmp (p, "lt-", 3) == 0)
	    p += 3;
	  po->po_program_name = p;
	}
    }

  po->po_eopt = 0;
  po->po_arg_start = po->po_argi;
  po->po_arg_count = 0;
  po->po_permuted = 0;

  return 0;
}

void
parseopt_free (struct parseopt *po)
{
  if (po->po_flags & PARSEOPT_INITIALIZED)
    {
      free (po->po_optgrp);
      free (po->po_optptr);
      free (po->po_optidx);
      po->po_flags &= ~PARSEOPT_INITIALIZED;
    }
}

int
parseopt_parse (struct parseopt *po)
{
  int c;
  char *p;

  if ((c = parseopt_next (po, &p)) > 0)
    {
      assert (po->po_setopt != NULL);
      do
	po->po_setopt (po, c, p);
      while ((c = parseopt_next (po, &p)) > 0);
    }
  return c;
}

int
parseopt_getopt (struct parseopt *po, int argc, char **argv)
{
  int c;

  if (parseopt_init (po, argc, argv))
    return OPT_ERR;

  if (po->po_flags & PARSEOPT_EARLY)
    {
      c = parseopt_parse (po);
      if (c != OPT_END)
	return c;
      po->po_flags &= ~PARSEOPT_EARLY;

      po->po_argi = (po->po_flags & PARSEOPT_ARGV0) ? 0 : 1;
      po->po_eopt = 0;
      po->po_arg_start = po->po_argi;
      po->po_arg_count = 0;
      po->po_permuted = 0;
    }
  if (po->po_init_hook)
    po->po_init_hook (po);
  return parseopt_parse (po);
}

struct optdef *
parseopt_optdef_by_code (struct parseopt *po, int code)
{
  size_t i;

  for (i = 0; i < po->po_optcount; i++)
    {
      struct optdef *opt = po->po_optptr[po->po_optidx[i]];
      if (opt->opt_code == code)
	return opt;
    }
  return NULL;
}

struct optdef *
parseopt_optdef_by_name (struct parseopt *po, char const *name)
{
  size_t i;

  for (i = 0; i < po->po_optcount; i++)
    {
      struct optdef *opt = po->po_optptr[po->po_optidx[i]];
      if (strcmp (opt->opt_name, name) == 0)
	{
	  while (opt->opt_flags & OPTFLAG_ALIAS)
	    opt--;
	  return opt;
	}
    }
  return NULL;
}

int
parseopt_is_set (struct parseopt *po, int code)
{
  struct optdef *opt = parseopt_optdef_by_code (po, code);
  if (opt)
    return !!(opt->opt_flags & OPTFLAG_IS_SET);
  return -1;
}

static inline void
position_init (struct position *pos, unsigned n)
{
  pos->off = pos->col = n;
}

static inline void
position_incr (struct position *pos, int nbytes)
{
  pos->off += nbytes;
  pos->col++;
}

static inline void
position_add (struct position *a, struct position *b)
{
  a->off += b->off;
  a->col += b->col;
}

static inline int
position_eq (struct position *a, struct position *b)
{
  return a->col == b->col;
}

static void
wordwrap_line_init (WORDWRAP_FILE wf, int clrws)
{
  position_init (&wf->cur, wf->left_margin);
  wf->unibyte = 0;
  if (clrws)
    {
      position_init (&wf->ws_run, 0);
    }
}

static unsigned
detect_right_margin (WORDWRAP_FILE wf)
{
  struct winsize ws;
  unsigned r = 0;

  ws.ws_col = ws.ws_row = 0;
  if ((ioctl (wf->fd, TIOCGWINSZ, (char *) &ws) < 0) || ws.ws_col == 0)
    {
      char *p = getenv ("COLUMNS");
      if (p)
	{
	  unsigned long n;
	  char *ep;
	  errno = 0;
	  n = strtoul (p, &ep, 10);
	  if (!(errno || *ep || n > UINT_MAX))
	    r = n;
	}
      else
	r = DEFAULT_RIGHT_MARGIN;
    }
  else
    r = ws.ws_col;
  return r;
}

static ssize_t
_ww_fd_writer (void *data, const char *str, size_t n)
{
  WORDWRAP_FILE wf = data;
  return write (wf->fd, str, n);
}

WORDWRAP_FILE
wordwrap_open (int fd, ssize_t (*writer) (void *, const char *, size_t),
	       void *data)
{
  struct wordwrap_file *wf;
  int ec;

  if ((wf = calloc (1, sizeof (*wf))) == NULL)
    return NULL;
  if ((wf->fd = dup (fd)) == -1)
    {
      ec = errno;
      free (wf);
      errno = ec;
      return NULL;
    }
  wf->writer = writer;
  wf->stream = data;

  wf->word_start = UNSET;
  wf->next_left_margin = UNSET;

  wordwrap_set_right_margin (wf, 0);

  return wf;
}

WORDWRAP_FILE
wordwrap_fdopen (int fd)
{
  WORDWRAP_FILE wf = wordwrap_open (fd, _ww_fd_writer, NULL);
  wf->stream = wf;
  return wf;
}

int
wordwrap_close (WORDWRAP_FILE wf)
{
  int rc;

  rc = wordwrap_flush (wf);
  close (wf->fd);
  free (wf->buffer);
  free (wf);

  return rc;
}

int
wordwrap_at_bol (WORDWRAP_FILE wf)
{
  return wf->cur.col == wf->left_margin;
}

int
wordwrap_at_eol (WORDWRAP_FILE wf)
{
  return wf->cur.col == wf->right_margin;
}

static ssize_t
full_write (WORDWRAP_FILE wf, size_t size)
{
  ssize_t total = 0;

  while (total < size)
    {
      ssize_t n = wf->writer (wf->stream, wf->buffer + total, size - total);
      if (n == -1)
	{
	  wf->err = errno;
	  break;
	}
      if (n == 0)
	{
	  wf->err = ENOSPC;
	  break;
	}
      total += n;
    }
  return total;
}

static inline size_t
safe_mbrtowc (WORDWRAP_FILE wf, wchar_t *wc, const char *s, mbstate_t *ps)
{
  if (!wf->unibyte)
    {
      size_t n = mbrtowc (wc, s, MB_CUR_MAX, ps);
      if (n == (size_t) -1 || n == (size_t) -2)
	wf->unibyte = 1;
      else
	return n;
    }
  *wc = *(unsigned char *)s;
  return 1;
}

static size_t
wsprefix (WORDWRAP_FILE wf, char const *str, size_t size)
{
  size_t i;
  mbstate_t mbs;
  wchar_t wc;

  memset (&mbs, 0, sizeof (mbs));
  for (i = 0; i < size; )
    {
      size_t n = safe_mbrtowc (wf, &wc, &str[i], &mbs);

      if (!iswblank (wc))
	break;

      i += n;
    }

  return i;
}

static void
wordwrap_rescan (WORDWRAP_FILE wf, size_t size)
{
  mbstate_t mbs;
  wchar_t wc;

  wordwrap_line_init (wf, 0);

  memset (&mbs, 0, sizeof (mbs));
  while (wf->cur.off < size)
    {
      size_t n = safe_mbrtowc (wf, &wc, &wf->buffer[wf->cur.off], &mbs);

      if (iswblank (wc))
	{
	  if (!(wf->ws_run.col > 0 &&
		wf->last_ws.col + wf->ws_run.col == wf->cur.col))
	    {
	      wf->last_ws = wf->cur;
	      position_init (&wf->ws_run, 0);
	    }
	  position_incr (&wf->ws_run, n);
	}

      position_incr(&wf->cur, n);
    }
}

static struct position
wordwrap_last_ws (WORDWRAP_FILE wf, size_t size, struct position *last_ws)
{
  mbstate_t mbs;
  wchar_t wc;
  struct position cur = POSITION_INITIALIZER;
  struct position ws_run = POSITION_INITIALIZER;

  memset (&mbs, 0, sizeof (mbs));
  last_ws->off = last_ws->col = UNSET;
  while (cur.off < size)
    {
      size_t n = safe_mbrtowc (wf, &wc, &wf->buffer[cur.off], &mbs);
      if (iswblank (wc))
	{
	  if (!(ws_run.col > 0 && last_ws->col + ws_run.col == cur.col))
	    {
	      *last_ws = cur;
	      position_init (&ws_run, 0);
	    }
	  position_incr (&ws_run, n);
	}
      else
	{
	  position_init (last_ws, UNSET);
	  position_init (&ws_run, 0);
	}
      position_incr (&cur, n);
    }
  return cur;
}

static int
flush_line (WORDWRAP_FILE wf, size_t size)
{
  ssize_t n;
  struct position pos, last_ws;

  if (wf->ws_run.off > 0 && size == wf->last_ws.off + wf->ws_run.off)
    {
      pos = last_ws = wf->last_ws;
    }
  else
    {
      pos = wordwrap_last_ws (wf, size, &last_ws);
    }

  if ((pos.col >= wf->left_margin && wf->cur.col > wf->left_margin) ||
      size == wf->cur.off)
    {
      if (last_ws.off != UNSET)
	pos = last_ws;

      n = full_write (wf, pos.off);
      if (n == -1)
	return -1;

      if (n < pos.off)
	{
	  //FIXME
	  abort ();
	}
    }

  wf->writer (wf->stream, "\n", 1);

  if (ISSET (wf->next_left_margin))
    {
      wf->left_margin = wf->next_left_margin;
      wf->next_left_margin = UNSET;
    }

  n = wf->cur.off - size;
  if (n > 0)
    {
      size_t wsn;

      wsn = wsprefix (wf, wf->buffer + size, n);

      size += wsn;
      n -= wsn;

      if (n)
	{
	  memmove (wf->buffer + wf->left_margin, wf->buffer + size, n);
	  wf->cur.off = wf->left_margin + n;
	  position_init (&wf->ws_run, 0);
	}
    }

  if (wf->indent)
    {
      memset (wf->buffer, ' ', wf->left_margin);
      wf->indent = 0;
      position_init (&wf->last_ws, 0);
      position_init (&wf->ws_run, wf->left_margin);
    }

  wordwrap_rescan (wf, wf->left_margin + n);

  return 0;
}

int
wordwrap_flush (WORDWRAP_FILE wf)
{
  if (wf->cur.col > wf->left_margin)
    return flush_line (wf, wf->cur.off);
  return 0;
}

int
wordwrap_error (WORDWRAP_FILE wf)
{
  return wf->err;
}

int
wordwrap_set_left_margin (WORDWRAP_FILE wf, unsigned left)
{
  int bol;

  if (left == wf->left_margin)
    return 0;
  else if (left >= wf->right_margin)
    {
      wf->err = errno = EINVAL;
      return -1;
    }

  bol = wordwrap_at_bol (wf);
  wf->left_margin = left;
  wf->indent = 1;
  if (left < wf->cur.col ||
      (left == wf->cur.col && (wf->ws_run.col == 0 ||
			      wf->cur.col > wf->last_ws.col + wf->ws_run.col)))
    {
      if (!bol)
	flush_line (wf, wf->cur.off);//FIXME: remove trailing ws
      else
	wordwrap_line_init (wf, 1);
    }
  else if (left > wf->cur.col)
    {
      size_t n = wf->left_margin - wf->cur.col;
      if (n > 0)
	{
	  memset (wf->buffer + wf->cur.off, ' ', n);
	  wf->last_ws = wf->cur;
	  position_init (&wf->ws_run, n);
	  position_add (&wf->cur, &wf->ws_run);
	  wf->unibyte = 0;
	}
      else
	wordwrap_line_init (wf, 1);
    }
  return 0;
}

int
wordwrap_next_left_margin (WORDWRAP_FILE wf, unsigned left)
{
  if (left == wf->left_margin)
    return 0;
  else if (left >= wf->right_margin)
    {
      wf->err = errno = EINVAL;
      return -1;
    }
  wf->next_left_margin = left;
  wf->indent = 1;
  return 0;
}

int
wordwrap_set_right_margin (WORDWRAP_FILE wf, unsigned right)
{
  if (right == 0)
    right = detect_right_margin (wf);

  if (right == wf->right_margin)
    return 0;
  else if (right <= wf->left_margin)
    {
      wf->err = errno = EINVAL;
      return -1;
    }
  else
    {
      char *p;
      size_t size;

      if (right < wf->cur.off)
	{
	  if (wordwrap_flush (wf))
	    return -1;
	}

      size = MB_CUR_MAX * (right + 1);
      p = realloc (wf->buffer, size);
      if (!p)
	{
	  wf->err = errno;
	  return -1;
	}

      wf->buffer = p;
      wf->bufsize = size;
      wf->right_margin = right;
    }

  return 0;
}

void
wordwrap_word_start (WORDWRAP_FILE wf)
{
  wf->word_start = wf->cur.off;
}

void
wordwrap_word_end (WORDWRAP_FILE wf)
{
  wf->word_start = UNSET;
}

int
wordwrap_write (WORDWRAP_FILE wf, char const *str, size_t len)
{
  size_t i;
  wchar_t wc;
  mbstate_t mbs;

  memset (&mbs, 0, sizeof (mbs));
  for (i = 0; i < len; )
    {
      size_t n = safe_mbrtowc (wf, &wc, &str[i], &mbs);

      if (wf->cur.col + 1 == wf->right_margin || wc == '\n')
	{
	  size_t len;

	  if (ISSET (wf->word_start))
	    {
	      len = wf->word_start;
	      wf->word_start = UNSET;
	    }
	  else if (!iswspace (wc) && wf->ws_run.off > 0 && wf->last_ws.off > 0)
	    len = wf->last_ws.off;
	  else
	    len = wf->cur.off;

	  flush_line (wf, len);
	  if (wc == '\n')
	    {
	      i += n;
	      continue;
	    }
	}

      if (iswblank (wc))
	{
	  if (wf->cur.col == wf->left_margin)
	    {
	      /* Skip leading whitespace */
	      i += n;
	      continue;
	    }
	  else if (!(wf->ws_run.col > 0 &&
		     wf->last_ws.col + wf->ws_run.col == wf->cur.col))
	    {
	      wf->last_ws = wf->cur;
	      position_init (&wf->ws_run, 0);
	    }
	  position_incr (&wf->ws_run, n);
	}

      memcpy (wf->buffer + wf->cur.off, str + i, n);

      position_incr (&wf->cur, n);
      i += n;
    }
  return 0;
}

int
wordwrap_puts (WORDWRAP_FILE wf, char const *str)
{
  return wordwrap_write (wf, str, strlen (str));
}

int
wordwrap_putc (WORDWRAP_FILE wf, int c)
{
  char ch = c;
  return wordwrap_write (wf, &ch, 1);
}

int
wordwrap_para (WORDWRAP_FILE wf)
{
  if (wordwrap_at_bol (wf))
    return wordwrap_write (wf, "\n", 1);
  else
    return wordwrap_write (wf, "\n\n", 2);
}

int
wordwrap_vprintf (WORDWRAP_FILE wf, char const *fmt, va_list ap)
{
  size_t buflen = 64;
  char *buf;
  ssize_t n;
  int rc;

  buf = malloc (buflen);
  if (!buf)
    {
      wf->err = errno;
      return -1;
    }

  for (;;)
    {
      va_list aq;

      va_copy (aq, ap);
      n = vsnprintf (buf, buflen, fmt, aq);
      va_end (aq);

      if (n < 0 || n >= buflen || !memchr(buf, '\0', n + 1))
	{
	  char *p;

	  if ((size_t) -1 / 3 * 2  <= buflen)
	    {
	      wf->err = ENOMEM;
	      free (buf);
	      return -1;
	    }

	  buflen += (buflen + 1) / 2;
	  p = realloc (buf, buflen);
	  if (!p)
	    {
	      wf->err = errno;
	      free (buf);
	      return -1;
	    }
	  buf = p;
	}
      else
	break;
    }

  rc = wordwrap_write (wf, buf, n);
  free (buf);
  return rc;
}

int
wordwrap_printf (WORDWRAP_FILE wf, char const *fmt, ...)
{
  va_list ap;
  int rc;

  va_start (ap, fmt);
  rc = wordwrap_vprintf (wf, fmt, ap);
  va_end (ap);
  return rc;
}

static inline int
is_name_char (struct wordsplit *wsp, int c)
{
	return ISALNUM (c)
		|| c == '_'
		|| ((wsp->ws_options & WRDSO_NAMECHAR)
		    && strchr (wsp->ws_namechar, c));
}

static void
_wsplt_alloc_die (struct wordsplit *wsp)
{
  wsp->ws_error ("%s", _("memory exhausted"));
  abort ();
}

static void
_wsplt_error (const char *fmt, ...)
{
  va_list ap;

  va_start (ap, fmt);
  vfprintf (stderr, fmt, ap);
  va_end (ap);
  fputc ('\n', stderr);
}

static int
_wsplt_seterr (struct wordsplit *wsp, int ec)
{
  wsp->ws_errno = ec;
  if (wsp->ws_flags & WRDSF_SHOWERR)
    wordsplit_perror (wsp);
  if (ec == WRDSE_USAGE)
    errno = EINVAL;
  return ec;
}

static int
_wsplt_nomem (struct wordsplit *wsp)
{
  errno = ENOMEM;
  wsp->ws_errno = WRDSE_NOSPACE;
  if (wsp->ws_flags & WRDSF_ENOMEMABRT)
    wsp->ws_alloc_die (wsp);
  if (wsp->ws_flags & WRDSF_SHOWERR)
    wordsplit_perror (wsp);
  if (!(wsp->ws_flags & WRDSF_REUSE))
    wordsplit_free (wsp);
  wordsplit_free_nodes (wsp);
  return wsp->ws_errno;
}

static void
_wsplt_store_errctx (struct wordsplit *wsp, char const *str, size_t len)
{
  free (wsp->ws_errctx);
  wsp->ws_errctx = malloc (len + 1);
  if (!wsp->ws_errctx)
    {
      wsp->ws_error ("%s",
		     _("memory exhausted while trying to store error context"));
    }
  else
    {
      memcpy (wsp->ws_errctx, str, len);
      wsp->ws_errctx[len] = 0;
    }
}

static inline int
_wsplt_setctxerr (struct wordsplit *wsp, int ec, char const *str, size_t len)
{
  _wsplt_store_errctx (wsp, str, len);
  return _wsplt_seterr (wsp, ec);
}

static int
_wsplt_subsplit (struct wordsplit *wsp, struct wordsplit *wss,
		 char const *str, int len,
		 int flags, int finalize)
{
  int rc;

  wss->ws_delim = wsp->ws_delim;
  wss->ws_debug = wsp->ws_debug;
  wss->ws_error = wsp->ws_error;
  wss->ws_alloc_die = wsp->ws_alloc_die;

  if (!(flags & WRDSF_NOVAR))
    {
      wss->ws_env = wsp->ws_env;
      wss->ws_getvar = wsp->ws_getvar;
      flags |= wsp->ws_flags & (WRDSF_ENV | WRDSF_ENV_KV | WRDSF_GETVAR);
    }
  if (!(flags & WRDSF_NOCMD))
    {
      wss->ws_command = wsp->ws_command;
    }

  if ((flags & (WRDSF_NOVAR|WRDSF_NOCMD)) != (WRDSF_NOVAR|WRDSF_NOCMD))
    {
      wss->ws_closure = wsp->ws_closure;
      flags |= wsp->ws_flags & WRDSF_CLOSURE;
    }

  wss->ws_options = wsp->ws_options & ~WRDSO_MAXWORDS;
  wss->ws_namechar = wsp->ws_namechar;

  flags |= WRDSF_DELIM
	 | WRDSF_ALLOC_DIE
	 | WRDSF_ERROR
	 | WRDSF_DEBUG
	 | (wsp->ws_flags & (WRDSF_SHOWDBG | WRDSF_SHOWERR | WRDSF_OPTIONS));

  rc = wordsplit_init (wss, str, len, flags);
  if (rc)
    return rc;
  wss->ws_lvl = wsp->ws_lvl + 1;
  rc = wordsplit_process_list (wss, 0);
  if (rc)
    {
      wordsplit_free_nodes (wss);
      return rc;
    }
  if (finalize)
    {
      rc = wordsplit_finish (wss);
      wordsplit_free_nodes (wss);
    }
  return rc;
}

static void
_wsplt_seterr_sub (struct wordsplit *wsp, struct wordsplit *wss)
{
  /* Clear user-defined error */
  if (wsp->ws_errno == WRDSE_USERERR)
    free (wsp->ws_usererr);
  /* Copy error state */
  wsp->ws_errno = wss->ws_errno;
  if (wss->ws_errno == WRDSE_USERERR)
    {
      wsp->ws_usererr = wss->ws_usererr;
      wss->ws_errno = WRDSE_EOF;
      wss->ws_usererr = NULL;
    }
  /* Copy error context */
  free (wsp->ws_errctx);
  wsp->ws_errctx = wss->ws_errctx;
  wss->ws_errctx = NULL;
}

static void
wordsplit_init0 (struct wordsplit *wsp)
{
  if (wsp->ws_flags & WRDSF_REUSE)
    {
      if (!(wsp->ws_flags & WRDSF_APPEND))
	wordsplit_free_words (wsp);
      wordsplit_clearerr (wsp);
    }
  else
    {
      wsp->ws_wordv = NULL;
      wsp->ws_wordc = 0;
      wsp->ws_wordn = 0;
    }

  wsp->ws_errno = 0;
}

static int
wordsplit_init (struct wordsplit *wsp, const char *input, size_t len,
		int flags)
{
  wsp->ws_flags = flags;

  if (!(wsp->ws_flags & WRDSF_ALLOC_DIE))
    wsp->ws_alloc_die = _wsplt_alloc_die;
  if (!(wsp->ws_flags & WRDSF_ERROR))
    wsp->ws_error = _wsplt_error;

  if (!(wsp->ws_flags & WRDSF_NOVAR))
    {
      /* These will be initialized on first variable assignment */
      wsp->ws_envidx = wsp->ws_envsiz = 0;
      wsp->ws_envbuf = NULL;
    }

  if (!(wsp->ws_flags & WRDSF_NOCMD))
    {
      if (!wsp->ws_command)
	return _wsplt_seterr (wsp, WRDSE_USAGE);
    }

  if (wsp->ws_flags & WRDSF_SHOWDBG)
    {
      if (!(wsp->ws_flags & WRDSF_DEBUG))
	{
	  if (wsp->ws_flags & WRDSF_ERROR)
	    wsp->ws_debug = wsp->ws_error;
	  else if (wsp->ws_flags & WRDSF_SHOWERR)
	    wsp->ws_debug = _wsplt_error;
	  else
	    wsp->ws_flags &= ~WRDSF_SHOWDBG;
	}
    }

  wsp->ws_input = input;
  wsp->ws_len = len;

  if (!(wsp->ws_flags & WRDSF_DOOFFS))
    wsp->ws_offs = 0;

  if (!(wsp->ws_flags & WRDSF_DELIM))
    wsp->ws_delim = " \t\n";

  wsp->ws_sep[0] = wsp->ws_delim[0];
  wsp->ws_sep[1] = 0;

  if (!(wsp->ws_flags & WRDSF_COMMENT))
    wsp->ws_comment = NULL;

  if (!(wsp->ws_flags & WRDSF_CLOSURE))
    wsp->ws_closure = NULL;

  if (!(wsp->ws_flags & WRDSF_OPTIONS))
    wsp->ws_options = 0;

  if (wsp->ws_flags & WRDSF_ESCAPE)
    {
      if (!wsp->ws_escape[WRDSX_WORD])
	wsp->ws_escape[WRDSX_WORD] = "";
      if (!wsp->ws_escape[WRDSX_QUOTE])
	wsp->ws_escape[WRDSX_QUOTE] = "";
    }
  else if (wsp->ws_flags & WRDSF_CESCAPES)
    {
      wsp->ws_escape[WRDSX_WORD] = wordsplit_escape[WS_ESC_C_WS];
      wsp->ws_escape[WRDSX_QUOTE] = wordsplit_escape[WS_ESC_C];
      wsp->ws_options |= WRDSO_OESC_QUOTE | WRDSO_OESC_WORD
		      | WRDSO_XESC_QUOTE | WRDSO_XESC_WORD;
    }
  else
    {
      wsp->ws_escape[WRDSX_WORD] = "";
      wsp->ws_escape[WRDSX_QUOTE] = "";
    }

  if (!(wsp->ws_options & WRDSO_PARAMV))
    {
      wsp->ws_paramv = NULL;
      wsp->ws_paramc = 0;
    }
  wsp->ws_paramidx = wsp->ws_paramsiz = 0;
  wsp->ws_parambuf = NULL;

  if (wsp->ws_options & WRDSO_NAMECHAR)
    {
      if (wsp->ws_namechar[strcspn(wsp->ws_namechar, "${}*@-+?=")])
	return _wsplt_seterr (wsp, WRDSE_USAGE);
    }
  else
    wsp->ws_namechar = NULL;

  wsp->ws_endp = 0;
  wsp->ws_wordi = 0;

  if (wsp->ws_flags & WRDSF_REUSE)
    wordsplit_free_nodes (wsp);
  wsp->ws_head = wsp->ws_tail = NULL;

  wsp->ws_errctx = NULL;

  wordsplit_init0 (wsp);

  return 0;
}

static int
alloc_space (struct wordsplit *wsp, size_t count)
{
  size_t offs = (wsp->ws_flags & WRDSF_DOOFFS) ? wsp->ws_offs : 0;
  char **ptr;
  size_t newalloc;

  if (wsp->ws_wordv == NULL)
    {
      newalloc = offs + count > ALLOC_INIT ? count : ALLOC_INIT;
      ptr = calloc (newalloc, sizeof (ptr[0]));
    }
  else if (wsp->ws_wordn < offs + wsp->ws_wordc + count)
    {
      newalloc = offs + wsp->ws_wordc +
	(count > ALLOC_INCR ? count : ALLOC_INCR);
      ptr = realloc (wsp->ws_wordv, newalloc * sizeof (ptr[0]));
    }
  else
    return 0;

  if (ptr)
    {
      wsp->ws_wordn = newalloc;
      wsp->ws_wordv = ptr;
    }
  else
    return _wsplt_nomem (wsp);
  return 0;
}

static const char *
wsnode_flagstr (int flags)
{
  static char retbuf[7];
  char *p = retbuf;

  if (flags & _WSNF_WORD)
    *p++ = 'w';
  else if (flags & _WSNF_NULL)
    *p++ = 'n';
  else
    *p++ = '-';
  if (flags & _WSNF_QUOTE)
    *p++ = 'q';
  else
    *p++ = '-';
  if (flags & _WSNF_NOEXPAND)
    *p++ = 'E';
  else
    *p++ = '-';
  if (flags & _WSNF_JOIN)
    *p++ = 'j';
  else
    *p++ = '-';
  if (flags & _WSNF_SEXP)
    *p++ = 's';
  else
    *p++ = '-';
  if (flags & _WSNF_DELIM)
    *p++ = 'd';
  else
    *p++ = '-';
  *p = 0;
  return retbuf;
}

static const char *
wsnode_ptr (struct wordsplit *wsp, struct wordsplit_node *p)
{
  if (p->flags & _WSNF_NULL)
    return "";
  else if (p->flags & _WSNF_WORD)
    return p->v.word;
  else
    return wsp->ws_input + p->v.segm.beg;
}

static size_t
wsnode_len (struct wordsplit_node *p)
{
  if (p->flags & _WSNF_NULL)
    return 0;
  else if (p->flags & _WSNF_WORD)
    return strlen (p->v.word);
  else
    return p->v.segm.end - p->v.segm.beg;
}

static int
wsnode_new (struct wordsplit *wsp, struct wordsplit_node **pnode)
{
  struct wordsplit_node *node = calloc (1, sizeof (*node));
  if (!node)
    return _wsplt_nomem (wsp);
  *pnode = node;
  return 0;
}

static void
wsnode_free (struct wordsplit_node *p)
{
  if ((p->flags & (_WSNF_WORD|_WSNF_CONST)) == _WSNF_WORD)
    free (p->v.word);
  free (p);
}

static void
wsnode_append (struct wordsplit *wsp, struct wordsplit_node *node)
{
  node->next = NULL;
  node->prev = wsp->ws_tail;
  if (wsp->ws_tail)
    wsp->ws_tail->next = node;
  else
    wsp->ws_head = node;
  wsp->ws_tail = node;
}

static void
wsnode_remove (struct wordsplit *wsp, struct wordsplit_node *node)
{
  struct wordsplit_node *p;

  p = node->prev;
  if (p)
    {
      p->next = node->next;
      if (!node->next)
	p->flags &= ~_WSNF_JOIN;
    }
  else
    wsp->ws_head = node->next;

  p = node->next;
  if (p)
    p->prev = node->prev;
  else
    wsp->ws_tail = node->prev;

  wsnode_free (node);
}

static struct wordsplit_node *
wsnode_tail (struct wordsplit_node *p)
{
  while (p && p->next)
    p = p->next;
  return p;
}

static void
wsnode_insert (struct wordsplit *wsp, struct wordsplit_node *node,
	       struct wordsplit_node *anchor, int before)
{
  if (!wsp->ws_head)
    {
      node->next = node->prev = NULL;
      wsp->ws_head = wsp->ws_tail = node;
    }
  else if (before)
    {
      if (anchor->prev)
	wsnode_insert (wsp, node, anchor->prev, 0);
      else
	{
	  struct wordsplit_node *tail = wsnode_tail (node);
	  node->prev = NULL;
	  tail->next = anchor;
	  anchor->prev = tail;
	  wsp->ws_head = node;
	}
    }
  else
    {
      struct wordsplit_node *p;
      struct wordsplit_node *tail = wsnode_tail (node);

      p = anchor->next;
      if (p)
	p->prev = tail;
      else
	wsp->ws_tail = tail;
      tail->next = p;
      node->prev = anchor;
      anchor->next = node;
    }
}

static int
wordsplit_add_segm (struct wordsplit *wsp, size_t beg, size_t end, int flg)
{
  struct wordsplit_node *node;
  int rc;

  if (end == beg && !(flg & _WSNF_EMPTYOK))
    return 0;
  rc = wsnode_new (wsp, &node);
  if (rc)
    return rc;
  node->flags = flg & ~(_WSNF_WORD | _WSNF_EMPTYOK);
  node->v.segm.beg = beg;
  node->v.segm.end = end;
  wsnode_append (wsp, node);
  return 0;
}

static void
wordsplit_free_nodes (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p;)
    {
      struct wordsplit_node *next = p->next;
      wsnode_free (p);
      p = next;
    }
  wsp->ws_head = wsp->ws_tail = NULL;
}

static void
wordsplit_dump_nodes (struct wordsplit *wsp)
{
  struct wordsplit_node *p;
  int n = 0;

  for (p = wsp->ws_head, n = 0; p; p = p->next, n++)
    {
      if (p->flags & _WSNF_WORD)
	wsp->ws_debug ("(%02d) %4d: %p: %#04x (%s):%s;",
		       wsp->ws_lvl,
		       n, p, p->flags, wsnode_flagstr (p->flags), p->v.word);
      else
	wsp->ws_debug ("(%02d) %4d: %p: %#04x (%s):%.*s;",
		       wsp->ws_lvl,
		       n, p, p->flags, wsnode_flagstr (p->flags),
		       (int) (p->v.segm.end - p->v.segm.beg),
		       wsp->ws_input + p->v.segm.beg);
    }
}

static int
coalesce_segment (struct wordsplit *wsp, struct wordsplit_node *node)
{
  struct wordsplit_node *p, *end;
  size_t len = 0;
  char *buf, *cur;
  int stop;

  if (!(node->flags & _WSNF_JOIN))
    return 0;

  for (p = node; p && (p->flags & _WSNF_JOIN); p = p->next)
    {
      len += wsnode_len (p);
    }
  if (p)
    len += wsnode_len (p);
  end = p;

  buf = malloc (len + 1);
  if (!buf)
    return _wsplt_nomem (wsp);
  cur = buf;

  p = node;
  for (stop = 0; !stop;)
    {
      struct wordsplit_node *next = p->next;
      const char *str = wsnode_ptr (wsp, p);
      size_t slen = wsnode_len (p);

      memcpy (cur, str, slen);
      cur += slen;
      if (p != node)
	{
	  node->flags |= p->flags & _WSNF_QUOTE;
	  stop = p == end;
	  wsnode_remove (wsp, p);
	}
      p = next;
    }

  *cur = 0;

  node->flags &= ~_WSNF_JOIN;

  if (node->flags & _WSNF_WORD)
    free (node->v.word);
  else
    node->flags |= _WSNF_WORD;
  node->v.word = buf;
  return 0;
}

static int
wsnode_quoteremoval (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p; p = p->next)
    {
      const char *str = wsnode_ptr (wsp, p);
      size_t slen = wsnode_len (p);

      if (!(p->flags & _WSNF_NOEXPAND))
	{
	  if (!(p->flags & _WSNF_WORD))
	    {
	      char *newstr = malloc (slen + 1);
	      if (!newstr)
		return _wsplt_nomem (wsp);
	      memcpy (newstr, str, slen);
	      newstr[slen] = 0;
	      p->v.word = newstr;
	      p->flags |= _WSNF_WORD;
	    }

	  wordsplit_string_unquote_copy (wsp, p->flags & _WSNF_QUOTE,
					 p->v.word, str, slen);
	}
    }
  return 0;
}

static int
wsnode_coalesce (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p; p = p->next)
    {
      if (p->flags & _WSNF_JOIN)
	if (coalesce_segment (wsp, p))
	  return 1;
    }
  return 0;
}

static int
wsnode_tail_coalesce (struct wordsplit *wsp, struct wordsplit_node *p)
{
  if (p->next)
    {
      struct wordsplit_node *np = p;
      while (np && np->next)
	{
	  np->flags |= _WSNF_JOIN;
	  np = np->next;
	}
      if (coalesce_segment (wsp, p))
	return 1;
    }
  return 0;
}

static int
wordsplit_finish (struct wordsplit *wsp)
{
  struct wordsplit_node *p;
  size_t n;

  /* Postprocess delimiters. It would be rather simple, if it weren't for
     the incremental operation.

     Nodes of type _WSNF_DELIM get inserted to the node list if either
     WRDSF_RETURN_DELIMS flag or WRDSO_MAXWORDS option is set.

     The following cases should be distinguished:

     1. If both WRDSF_SQUEEZE_DELIMS and WRDSF_RETURN_DELIMS are set, compress
	any runs of similar delimiter nodes to a single node. The nodes are
	'similar' if they point to the same delimiter character.

	If WRDSO_MAXWORDS option is set, stop compressing when
	ws_wordi + 1 == ws_maxwords, and coalesce the rest of nodes into
	a single last node.

     2. If WRDSO_MAXWORDS option is set, but WRDSF_RETURN_DELIMS is not,
	remove any delimiter nodes. Stop operation when
	ws_wordi + 1 == ws_maxwords, and coalesce the rest of nodes into
	a single last node.

     3. If incremental operation is in progress, restart the loop any time
	a delimiter node is about to be returned, unless WRDSF_RETURN_DELIMS
	is set.
  */
 again:
  n = 0;             /* Number of words processed so far */
  p = wsp->ws_head;  /* Current node */

  while (p)
    {
      struct wordsplit_node *next = p->next;
      if (p->flags & _WSNF_DELIM)
	{
	  if (wsp->ws_flags & WRDSF_SQUEEZE_DELIMS)
	    {
	      if (next)
		{
		  if ((next->flags & _WSNF_DELIM) &&
		      (wsnode_ptr (wsp, p))[0] == (wsnode_ptr (wsp, next))[0])
		    {
		      wsnode_remove (wsp, p);
		      p = next;
		      continue;
		    }
		}
	      else if (wsp->ws_flags & WRDSF_INCREMENTAL)
		goto restart;
	    }
	  else if ((next && (next->flags & _WSNF_DELIM)) &&
		   (!(wsp->ws_options & WRDSO_RETDELNOTEMPTY)))
	    {
	      int rc;
	      struct wordsplit_node *nulnode;
	      if ((rc = wsnode_new (wsp, &nulnode)) != 0)
		return rc;
	      nulnode->flags = _WSNF_NULL | _WSNF_NOEXPAND;
	      wsnode_insert (wsp, nulnode, p, 0);
	      next = nulnode;
	    }

	  if ((wsp->ws_options & WRDSO_MAXWORDS) &&
	      !(wsp->ws_flags & WRDSF_RETURN_DELIMS))
	    {
	      wsnode_remove (wsp, p);
	      p = next;
	      continue;
	    }
	}

      n++;

      if ((wsp->ws_options & WRDSO_MAXWORDS) &&
	  (wsp->ws_wordi + n == wsp->ws_maxwords))
	  break;

      if (wsp->ws_flags & WRDSF_INCREMENTAL)
	p = NULL; /* Break the loop */
      else
	p = next;
    }

  if (p)
    {
      /* We're here if WRDSO_MAXWORDS is in effect and wsp->ws_maxwords
	 words have already been collected. Reconstruct a single final
	 node from the remaining nodes. */
      if (wsnode_tail_coalesce (wsp, p))
	return wsp->ws_errno;
      n++;
    }

  if (n == 0)
    {
      /* The loop above have eliminated all nodes. */
      if (wsp->ws_flags & WRDSF_INCREMENTAL)
	{
	  /* Restart the processing, if there's any input left. */
	restart:
	  if (wsp->ws_endp < wsp->ws_len)
	    {
	      int rc;
	      if (wsp->ws_flags & WRDSF_SHOWDBG)
		wsp->ws_debug (_("Restarting"));
	      rc = wordsplit_process_list (wsp, skip_delim (wsp));
	      if (rc)
		return rc;
	    }
	  else
	    {
	      wsp->ws_errno = WRDSE_EOF;
	      return WRDSE_EOF;
	    }
	  goto again;
	}

      if (wsp->ws_flags & WRDSF_NOSPLIT)
	{
	  if (wordsplit_add_segm (wsp, 0, 0, _WSNF_EMPTYOK))
	    return wsp->ws_errno;
	  n = 1;
	}
    }

  if (alloc_space (wsp, n + 1))
    return wsp->ws_errno;

  while (wsp->ws_head)
    {
      const char *str = wsnode_ptr (wsp, wsp->ws_head);
      size_t slen = wsnode_len (wsp->ws_head);
      char *newstr = malloc (slen + 1);

      /* Assign newstr first, even if it is NULL.  This way
	 wordsplit_free will work even if we return
	 nomem later. */
      wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc] = newstr;
      if (!newstr)
	return _wsplt_nomem (wsp);
      memcpy (newstr, str, slen);
      newstr[slen] = 0;

      wsnode_remove (wsp, wsp->ws_head);

      wsp->ws_wordc++;
      wsp->ws_wordi++;

      if (wsp->ws_flags & WRDSF_INCREMENTAL)
	break;
    }
  wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc] = NULL;
  return 0;
}

int
wordsplit_append (wordsplit_t *wsp, int argc, char **argv)
{
  int rc;
  size_t i;

  rc = alloc_space (wsp, wsp->ws_wordc + argc + 1);
  if (rc)
    return rc;
  for (i = 0; i < argc; i++)
    {
      char *newstr = strdup (argv[i]);
      if (!newstr)
	{
	  while (i > 0)
	    {
	      free (wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc + i - 1]);
	      wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc + i - 1] = NULL;
	      i--;
	    }
	  return _wsplt_nomem (wsp);
	}
      wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc + i] = newstr;
    }
  wsp->ws_wordc += i;
  wsp->ws_wordv[wsp->ws_offs + wsp->ws_wordc] = NULL;
  return 0;
}

static int
node_split_prefix (struct wordsplit *wsp,
		   struct wordsplit_node **ptail,
		   struct wordsplit_node *node,
		   size_t beg, size_t len, int flg)
{
  struct wordsplit_node *newnode;

  if (len == 0)
    return 0;
  if (wsnode_new (wsp, &newnode))
    return 1;
  wsnode_insert (wsp, newnode, *ptail, 0);
  if (node->flags & _WSNF_WORD)
    {
      const char *str = wsnode_ptr (wsp, node);
      char *newstr = malloc (len + 1);
      if (!newstr)
	return _wsplt_nomem (wsp);
      memcpy (newstr, str + beg, len);
      newstr[len] = 0;
      newnode->flags = _WSNF_WORD;
      newnode->v.word = newstr;
    }
  else
    {
      newnode->v.segm.beg = node->v.segm.beg + beg;
      newnode->v.segm.end = newnode->v.segm.beg + len;
    }
  newnode->flags |= flg;
  *ptail = newnode;
  return 0;
}

static int
find_closing_paren (const char *str, size_t i, size_t len, size_t *poff,
		    char const *paren)
{
  enum { st_init, st_squote, st_dquote } state = st_init;
  size_t level = 1;

  for (; i < len; i++)
    {
      switch (state)
	{
	case st_init:
	  switch (str[i])
	    {
	    default:
	      if (str[i] == paren[0])
		{
		  level++;
		  break;
		}
	      else if (str[i] == paren[1])
		{
		  if (--level == 0)
		    {
		      *poff = i;
		      return 0;
		    }
		  break;
		}
	      break;

	    case '"':
	      state = st_dquote;
	      break;

	    case '\'':
	      state = st_squote;
	      break;
	    }
	  break;

	case st_squote:
	  if (str[i] == '\'')
	    state = st_init;
	  break;

	case st_dquote:
	  if (str[i] == '\\')
	    i++;
	  else if (str[i] == '"')
	    state = st_init;
	  break;
	}
    }
  return 1;
}

static char const *
wsplt_env_find (struct wordsplit *wsp, const char *name, size_t len)
{
  size_t i;

  if (!wsp->ws_env)
    return NULL;
  if (wsp->ws_flags & WRDSF_ENV_KV)
    {
      /* A key-value pair environment */
      for (i = 0; wsp->ws_env[i]; i++)
	{
	  size_t elen = strlen (wsp->ws_env[i]);
	  if (elen == len && memcmp (wsp->ws_env[i], name, elen) == 0)
	    return wsp->ws_env[i + 1];
	  /* Skip the value.  Break the loop if it is NULL. */
	  i++;
	  if (wsp->ws_env[i] == NULL)
	    break;
	}
    }
  else
    {
      /* Usual (A=B) environment. */
      for (i = 0; wsp->ws_env[i]; i++)
	{
	  size_t j;
	  const char *var = wsp->ws_env[i];

	  for (j = 0; j < len; j++)
	    if (name[j] != var[j])
	      break;
	  if (j == len && var[j] == '=')
	    return var + j + 1;
	}
    }
  return NULL;
}

static int
wsplt_env_lookup (struct wordsplit *wsp, const char *name, size_t len,
		  char **ret)
{
  if (wsp->ws_flags & WRDSF_ENV)
    {
      char const *val = wsplt_env_find (wsp, name, len);
      if (val)
	{
	  char *retval = strdup (val);
	  if (!retval)
	    return WRDSE_NOSPACE;
	  *ret = retval;
	  return WRDSE_OK;
	}
    }
  return WRDSE_UNDEF;
}

static int
wsplt_env_getvar (struct wordsplit *wsp, const char *name, size_t len,
		  char **ret)
{
  return wsp->ws_getvar (ret, name, len, wsp->ws_closure);
}

static int
wsplt_assign_var (struct wordsplit *wsp, const char *name, size_t namelen,
		  char const *value)
{
  int n = (wsp->ws_flags & WRDSF_ENV_KV) ? 2 : 1;
  char *v;

  if (wsp->ws_envidx + n >= wsp->ws_envsiz)
    {
      size_t sz;
      char **newenv;

      if (!wsp->ws_envbuf)
	{
	  if (wsp->ws_flags & WRDSF_ENV)
	    {
	      size_t i = 0, j;

	      if (wsp->ws_env)
		{
		  for (; wsp->ws_env[i]; i++)
		    ;
		}

	      sz = i + n + 1;

	      newenv = calloc (sz, sizeof(newenv[0]));
	      if (!newenv)
		return _wsplt_nomem (wsp);

	      for (j = 0; j < i; j++)
		{
		  newenv[j] = strdup (wsp->ws_env[j]);
		  if (!newenv[j])
		    {
		      for (; j > 1; j--)
			free (newenv[j-1]);
		      free (newenv);
		      return _wsplt_nomem (wsp);
		    }
		}
	      newenv[j] = NULL;

	      wsp->ws_envbuf = newenv;
	      wsp->ws_envidx = i;
	      wsp->ws_envsiz = sz;
	      wsp->ws_env = (const char**) wsp->ws_envbuf;
	    }
	  else
	    {
	      newenv = calloc (WORDSPLIT_ENV_INIT, sizeof(newenv[0]));
	      if (!newenv)
		return _wsplt_nomem (wsp);
	      wsp->ws_envbuf = newenv;
	      wsp->ws_envidx = 0;
	      wsp->ws_envsiz = WORDSPLIT_ENV_INIT;
	      wsp->ws_env = (const char**) wsp->ws_envbuf;
	      wsp->ws_flags |= WRDSF_ENV;
	    }
	}
      else
	{
	  size_t n = wsp->ws_envsiz;

	  if ((size_t) -1 / 3 * 2 / sizeof (wsp->ws_envbuf[0]) <= n)
	    return _wsplt_nomem (wsp);
	  n += (n + 1) / 2;
	  newenv = realloc (wsp->ws_envbuf, n * sizeof (wsp->ws_envbuf[0]));
	  if (!newenv)
	    return _wsplt_nomem (wsp);
	  wsp->ws_envbuf = newenv;
	  wsp->ws_envsiz = n;
	  wsp->ws_env = (const char**) wsp->ws_envbuf;
	}
    }

  if (wsp->ws_flags & WRDSF_ENV_KV)
    {
      /* A key-value pair environment */
      char *p = malloc (namelen + 1);
      if (!p)
	return _wsplt_nomem (wsp);
      memcpy (p, name, namelen);
      p[namelen] = 0;

      v = strdup (value);
      if (!v)
	{
	  free (p);
	  return _wsplt_nomem (wsp);
	}
      wsp->ws_env[wsp->ws_envidx++] = p;
      wsp->ws_env[wsp->ws_envidx++] = v;
    }
  else
    {
      v = malloc (namelen + strlen(value) + 2);
      if (!v)
	return _wsplt_nomem (wsp);
      memcpy (v, name, namelen);
      v[namelen++] = '=';
      strcpy(v + namelen, value);
      wsp->ws_env[wsp->ws_envidx++] = v;
    }
  wsp->ws_env[wsp->ws_envidx] = NULL;
  return WRDSE_OK;
}

static int
wsplt_assign_param (struct wordsplit *wsp, int param_idx, char *value)
{
  char *v;

  if (param_idx < 0)
    return _wsplt_seterr (wsp, WRDSE_BADPARAM);
  if (param_idx == wsp->ws_paramc)
    {
      char **parambuf;
      if (!wsp->ws_parambuf)
	{
	  size_t i;

	  parambuf = calloc ((size_t)param_idx + 1, sizeof (parambuf[0]));
	  if (!parambuf)
	    return _wsplt_nomem (wsp);

	  for (i = 0; i < wsp->ws_paramc; i++)
	    {
	      parambuf[i] = strdup (wsp->ws_paramv[i]);
	      if (!parambuf[i])
		{
		  for (; i > 1; i--)
		    free (parambuf[i-1]);
		  free (parambuf);
		  return _wsplt_nomem (wsp);
		}
	    }

	  wsp->ws_parambuf = parambuf;
	  wsp->ws_paramidx = param_idx;
	  wsp->ws_paramsiz = param_idx + 1;
	}
      else
	{
	  size_t n = wsp->ws_paramsiz;

	  if ((size_t) -1 / 3 * 2 / sizeof (wsp->ws_parambuf[0]) <= n)
	    return _wsplt_nomem (wsp);
	  n += (n + 1) / 2;
	  parambuf = realloc (wsp->ws_parambuf, n * sizeof (wsp->ws_parambuf[0]));
	  if (!parambuf)
	    return _wsplt_nomem (wsp);
	  wsp->ws_parambuf = parambuf;
	  wsp->ws_paramsiz = n;
	  wsp->ws_parambuf[param_idx] = NULL;
	}

      wsp->ws_paramv = (const char**) wsp->ws_parambuf;
      wsp->ws_paramc = param_idx + 1;
    }
  else if (param_idx > wsp->ws_paramc)
    return _wsplt_seterr (wsp, WRDSE_BADPARAM);

  v = strdup (value);
  if (!v)
    return _wsplt_nomem (wsp);

  free (wsp->ws_parambuf[param_idx]);
  wsp->ws_parambuf[param_idx] = v;
  return WRDSE_OK;
}

static int
expvar_recover (struct wordsplit *wsp, const char *str,
		struct wordsplit_node **ptail, const char **pend, int flg)
{
  struct wordsplit_node *newnode;

  if (wsnode_new (wsp, &newnode))
    return 1;
  wsnode_insert (wsp, newnode, *ptail, 0);
  *ptail = newnode;
  newnode->flags = _WSNF_WORD | flg;
  newnode->v.word = malloc (3);
  if (!newnode->v.word)
    return _wsplt_nomem (wsp);
  newnode->v.word[0] = '$';
  newnode->v.word[1] = str[0];
  newnode->v.word[2] = 0;
  *pend = str;
  return 0;
}

static int
expand_paramv (struct wordsplit *wsp, struct wordsplit_node **ptail, int flg,
	       int q)
{
  struct wordsplit ws;
  int wsflags = WRDSF_NOVAR | WRDSF_NOCMD | WRDSF_QUOTE
	      | (WSP_RETURN_DELIMS (wsp) ? WRDSF_RETURN_DELIMS : 0)
	      | (q ? WRDSF_NOSPLIT : 0);
  size_t i;
  struct wordsplit_node *tail = *ptail;

  for (i = 0; i < wsp->ws_paramc; i++)
    {
      struct wordsplit_node *np;
      int rc = _wsplt_subsplit (wsp, &ws,
				wsp->ws_paramv[i], strlen (wsp->ws_paramv[i]),
				wsflags, q);
      if (rc)
	{
	  _wsplt_seterr_sub (wsp, &ws);
	  wordsplit_free (&ws);
	  return 1;
	}

      if (q)
	{
	  if (wsnode_new (wsp, &np))
	    return 1;
	  wsnode_insert (wsp, np, *ptail, 0);
	  *ptail = np;
	  np->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
	  np->v.word = ws.ws_wordv[0];

	  ws.ws_wordv[0] = NULL;
	}
      else
	{
	  for (np = ws.ws_head; np; np = np->next)
	    np->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
	  wsnode_insert (wsp, ws.ws_head, *ptail, 0);
	  *ptail = ws.ws_tail;
	  ws.ws_head = ws.ws_tail = NULL;
	}

      wsflags |= WRDSF_REUSE;
    }
  if (wsflags & WRDSF_REUSE)
    wordsplit_free (&ws);

  if (flg & _WSNF_QUOTE)
    {
      tail = tail->next;
      /* Insert delimiters, mark nodes as joinable */
      while (tail != *ptail)
	{
	  struct wordsplit_node *next = tail->next;
	  struct wordsplit_node *newnode;

	  tail->flags |= _WSNF_JOIN;

	  if (wsnode_new (wsp, &newnode))
	    return 1;
	  newnode->flags = _WSNF_WORD | _WSNF_CONST | _WSNF_NOEXPAND | _WSNF_JOIN;
	  newnode->v.word = wsp->ws_sep;

	  wsnode_insert (wsp, newnode, tail, 0);
	  tail = next;
	}
    }

  return 0;
}

static int
expvar (struct wordsplit *wsp, const char *str, size_t len,
	struct wordsplit_node **ptail, const char **pend, int flg)
{
  size_t i = 0;
  const char *defstr = NULL;
  char *value;
  struct wordsplit_node *newnode;
  const char *start = str - 1;
  int rc;
  struct wordsplit ws;
  int is_param = 0;
  long param_idx = 0;

  if (ISVARBEG (str[0]))
    {
      for (i = 1; i < len; i++)
	if (!is_name_char (wsp, str[i]))
	  break;
      *pend = str + i - 1;
    }
  else if ((wsp->ws_options & WRDSO_PARAMV) && ISDIGIT (str[0]))
    {
      i = 1;
      *pend = str;
      is_param = 1;
      param_idx = to_num (str[0]);
    }
  else if ((wsp->ws_options & WRDSO_PARAMV) && str[0] == '#')
    {
      char b[16];
      snprintf (b, sizeof(b), "%d", (int) wsp->ws_paramc);
      value = strdup (b);
      if (!value)
	return _wsplt_nomem (wsp);
      if (wsnode_new (wsp, &newnode))
	return 1;
      wsnode_insert (wsp, newnode, *ptail, 0);
      *ptail = newnode;
      newnode->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
      newnode->v.word = value;
      return 0;
    }
  else if ((wsp->ws_options & WRDSO_PARAMV) && str[0] == '*')
    {
      return expand_paramv (wsp, ptail, flg, 0);
    }
  else if ((wsp->ws_options & WRDSO_PARAMV) && str[0] == '@')
    {
      return expand_paramv (wsp, ptail, flg, 1);
    }
  else if (str[0] == '{'
	   && (ISVARBEG (str[1])
	       || (is_param = (((wsp->ws_options & WRDSO_PARAMV)
				&& ISDIGIT (str[1]))
			       || ((wsp->ws_options & WRDSO_PARAM_NEGIDX)
				   && (str[1] == '-'
				       && ISDIGIT (str[2]))))) != 0))
    {
      int i0 = str[1] == '-' ? 1 : 0;
      str++;
      len--;
      for (i = i0; i < len; i++)
	{
	  if (str[i] == '}')
	    {
	      defstr = NULL;
	      *pend = str + i;
	      break;
	    }
	  else if (strchr ("-+?=", str[i]))
	    {
	      size_t j;

	      defstr = str + i;
	      if (find_closing_paren (str, i, len, &j, "{}"))
		return _wsplt_seterr (wsp, WRDSE_CBRACE);
	      if (i > i0 + 1 && str[i-1] == ':')
		i--;
	      *pend = str + j;
	      break;
	    }
	  else if (is_param)
	    {
	      if (ISDIGIT (str[i]))
		{
		  param_idx = param_idx * 10 + to_num (str[i]);
		  if ((str[0] == '-' && -param_idx < INT_MIN)
		      || param_idx > INT_MAX)
		    return expvar_recover (wsp, str - 1, ptail, pend, flg);
		}
	      else
		{
		  return expvar_recover (wsp, str - 1, ptail, pend, flg);
		}
	    }
	  else if (!is_name_char (wsp, str[i]))
	    {
	      if (str[i] == ':' && i + 1 < len && strchr ("-+?=", str[i+1]))
		continue;
	      return expvar_recover (wsp, str - 1, ptail, pend, flg);
	    }
	}

      if (is_param && str[0] == '-')
	param_idx = wsp->ws_paramc - param_idx;

      if (i == len)
	return _wsplt_seterr (wsp, WRDSE_CBRACE);
    }
  else
    {
      return expvar_recover (wsp, str, ptail, pend, flg);
    }

  /* Actually expand the variable */
  /* str - start of the variable name
     i   - its length
     defstr - default replacement str */

  if (is_param)
    {
      if (param_idx >= 0 && param_idx < wsp->ws_paramc)
	{
	  value = strdup (wsp->ws_paramv[param_idx]);
	  if (!value)
	    rc = WRDSE_NOSPACE;
	  else
	    rc = WRDSE_OK;
	}
      else
	rc = WRDSE_UNDEF;
    }
  else
    {
      if (wsp->ws_flags & WRDSF_GETVAR)
	{
	  if (wsp->ws_options & WRDSO_GETVARPREF)
	    {
	      rc = wsplt_env_getvar (wsp, str, i, &value);
	      if (rc == WRDSE_UNDEF)
		rc = wsplt_env_lookup (wsp, str, i, &value);
	    }
	  else
	    {
	      rc = wsplt_env_lookup (wsp, str, i, &value);
	      if (rc == WRDSE_UNDEF)
		rc = wsplt_env_getvar (wsp, str, i, &value);
	    }
	}
      else
	rc = wsplt_env_lookup (wsp, str, i, &value);
    }

  if (rc == WRDSE_OK
      && (!value || value[0] == 0)
      && defstr && defstr[-1] == ':')
    {
      free (value);
      rc = WRDSE_UNDEF;
    }

  switch (rc)
    {
    case WRDSE_OK:
      if (defstr && *defstr == '+')
	{
	  size_t size = *pend - ++defstr;

	  rc = _wsplt_subsplit (wsp, &ws, defstr, size,
				WRDSF_NOSPLIT | WRDSF_WS | WRDSF_QUOTE |
				(wsp->ws_flags &
				 (WRDSF_NOVAR | WRDSF_NOCMD)), 1);
	  if (rc)
	    return rc;
	  free (value);
	  value = ws.ws_wordv[0];
	  ws.ws_wordv[0] = NULL;
	  wordsplit_free (&ws);
	}
      break;

    case WRDSE_UNDEF:
      if (defstr)
	{
	  size_t size;
	  if (*defstr == '-' || *defstr == '=')
	    {
	      size = *pend - ++defstr;

	      rc = _wsplt_subsplit (wsp, &ws, defstr, size,
				    WRDSF_NOSPLIT | WRDSF_WS | WRDSF_QUOTE |
				    (wsp->ws_flags &
				     (WRDSF_NOVAR | WRDSF_NOCMD)),
				    1);
	      if (rc)
		return rc;

	      value = ws.ws_wordv[0];
	      ws.ws_wordv[0] = NULL;
	      wordsplit_free (&ws);

	      if (defstr[-1] == '=')
		{
		  if (is_param)
		    rc = wsplt_assign_param (wsp, param_idx, value);
		  else
		    rc = wsplt_assign_var (wsp, str, i, value);
		}
	      if (rc)
		{
		  free (value);
		  return rc;
		}
	    }
	  else
	    {
	      if (*defstr == '?')
		{
		  size = *pend - ++defstr;
		  if (size == 0)
		    wsp->ws_error (_("%.*s: variable null or not set"),
				   (int) i, str);
		  else
		    {
		      rc = _wsplt_subsplit (wsp, &ws, defstr, size,
					    WRDSF_NOSPLIT | WRDSF_WS |
					    WRDSF_QUOTE |
					    (wsp->ws_flags &
					     (WRDSF_NOVAR | WRDSF_NOCMD)),
					    1);
		      if (rc == 0)
			wsp->ws_error ("%.*s: %s",
				       (int) i, str, ws.ws_wordv[0]);
		      else
			wsp->ws_error ("%.*s: %.*s",
				       (int) i, str, (int) size, defstr);
		      wordsplit_free (&ws);
		    }
		}
	      value = NULL;
	    }
	}
      else if (wsp->ws_flags & WRDSF_UNDEF)
	{
	  _wsplt_setctxerr (wsp, WRDSE_UNDEF, str, i);
	  return 1;
	}
      else
	{
	  if (wsp->ws_flags & WRDSF_WARNUNDEF)
	    wsp->ws_error (_("warning: undefined variable `%.*s'"),
			   (int) i, str);
	  if (wsp->ws_flags & WRDSF_KEEPUNDEF)
	    value = NULL;
	  else
	    {
	      value = strdup ("");
	      if (!value)
		return _wsplt_nomem (wsp);
	    }
	}
      break;

    case WRDSE_NOSPACE:
      return _wsplt_nomem (wsp);

    case WRDSE_USERERR:
      if (wsp->ws_errno == WRDSE_USERERR)
	free (wsp->ws_usererr);
      wsp->ws_usererr = value;
      /* fall through */
    default:
      _wsplt_seterr (wsp, rc);
      return 1;
    }

  if (value)
    {
      if (flg & _WSNF_QUOTE)
	{
	  if (wsnode_new (wsp, &newnode))
	    return 1;
	  wsnode_insert (wsp, newnode, *ptail, 0);
	  *ptail = newnode;
	  newnode->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
	  newnode->v.word = value;
	}
      else if (*value == 0)
	{
	  free (value);
	  /* Empty string is a special case */
	  if (wsnode_new (wsp, &newnode))
	    return 1;
	  wsnode_insert (wsp, newnode, *ptail, 0);
	  *ptail = newnode;
	  newnode->flags = _WSNF_NULL | _WSNF_NOEXPAND;
	}
      else
	{
	  struct wordsplit ws;
	  int rc;

	  rc = _wsplt_subsplit (wsp, &ws, value, strlen (value),
				WRDSF_NOVAR | WRDSF_NOCMD |
				WRDSF_QUOTE
				| (WSP_RETURN_DELIMS (wsp) ? WRDSF_RETURN_DELIMS : 0) ,
				0);
	  free (value);
	  if (rc)
	    {
	      _wsplt_seterr_sub (wsp, &ws);
	      wordsplit_free (&ws);
	      return 1;
	    }
	  wsnode_insert (wsp, ws.ws_head, *ptail, 0);
	  *ptail = ws.ws_tail;
	  ws.ws_head = ws.ws_tail = NULL;
	  wordsplit_free (&ws);
	}
    }
  else if (wsp->ws_flags & WRDSF_KEEPUNDEF)
    {
      size_t size = *pend - start + 1;

      if (wsnode_new (wsp, &newnode))
	return 1;
      wsnode_insert (wsp, newnode, *ptail, 0);
      *ptail = newnode;
      newnode->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
      newnode->v.word = malloc (size + 1);
      if (!newnode->v.word)
	return _wsplt_nomem (wsp);
      memcpy (newnode->v.word, start, size);
      newnode->v.word[size] = 0;
    }
  else
    {
      if (wsnode_new (wsp, &newnode))
	return 1;
      wsnode_insert (wsp, newnode, *ptail, 0);
      *ptail = newnode;
      newnode->flags = _WSNF_NULL | _WSNF_NOEXPAND;
    }
  return 0;
}

static int
begin_var_p (int c)
{
  return memchr ("{#@*", c, 4) != NULL || ISVARBEG (c) || ISDIGIT (c);
}

static int
node_expand (struct wordsplit *wsp, struct wordsplit_node *node,
	     int (*beg_p) (int),
	     int (*ws_exp_fn) (struct wordsplit *wsp,
			       const char *str, size_t len,
			       struct wordsplit_node **ptail,
			       const char **pend,
			       int flg))
{
  const char *str = wsnode_ptr (wsp, node);
  size_t slen = wsnode_len (node);
  const char *end = str + slen;
  const char *p;
  size_t off = 0;
  struct wordsplit_node *tail = node;

  for (p = str; p < end; p++)
    {
      if (*p == '\\')
	{
	  p++;
	  continue;
	}
      if (*p == '$' && beg_p (p[1]))
	{
	  size_t n = p - str;

	  if (tail != node)
	    tail->flags |= _WSNF_JOIN;
	  if (node_split_prefix (wsp, &tail, node, off, n, _WSNF_JOIN))
	    return 1;
	  p++;
	  if (ws_exp_fn (wsp, p, slen - n, &tail, &p,
			 node->flags & (_WSNF_JOIN | _WSNF_QUOTE)))
	    return 1;
	  off += p - str + 1;
	  str = p + 1;
	}
    }
  if (p > str)
    {
      if (tail != node)
	tail->flags |= _WSNF_JOIN;
      if (node_split_prefix (wsp, &tail, node, off, p - str,
			     node->flags & (_WSNF_JOIN|_WSNF_QUOTE)))
	return 1;
    }
  if (tail != node)
    {
      wsnode_remove (wsp, node);
    }
  return 0;
}

static void
wsnode_nullelim (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p;)
    {
      struct wordsplit_node *next = p->next;
      if (p->flags & _WSNF_DELIM && p->prev)
	p->prev->flags &= ~_WSNF_JOIN;
      if (p->flags & _WSNF_NULL)
	{
	  wsnode_remove (wsp, p);
	}
      p = next;
    }
}

static int
wordsplit_varexp (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p;)
    {
      struct wordsplit_node *next = p->next;
      if (!(p->flags & (_WSNF_NOEXPAND|_WSNF_DELIM)))
	if (node_expand (wsp, p, begin_var_p, expvar))
	  return 1;
      p = next;
    }

  wsnode_nullelim (wsp);
  return 0;
}

static int
begin_cmd_p (int c)
{
  return c == '(';
}

static int
expcmd (struct wordsplit *wsp, const char *str, size_t len,
	struct wordsplit_node **ptail, const char **pend, int flg)
{
  int rc;
  size_t j;
  char *value;
  struct wordsplit_node *newnode;
  struct wordsplit ws;

  str++;
  len--;

  if (find_closing_paren (str, 0, len, &j, "()"))
    {
      _wsplt_seterr (wsp, WRDSE_PAREN);
      return 1;
    }

  *pend = str + j;
  rc = _wsplt_subsplit (wsp, &ws, str, j, WRDSF_WS | WRDSF_QUOTE, 1);
  if (rc)
    {
      _wsplt_seterr_sub (wsp, &ws);
      wordsplit_free (&ws);
      return 1;
    }
  rc = wsp->ws_command (&value, str, j, ws.ws_wordv, wsp->ws_closure);
  wordsplit_free (&ws);

  if (rc == WRDSE_NOSPACE)
    return _wsplt_nomem (wsp);
  else if (rc)
    {
      if (rc == WRDSE_USERERR)
	{
	  if (wsp->ws_errno == WRDSE_USERERR)
	    free (wsp->ws_usererr);
	  wsp->ws_usererr = value;
	}
      _wsplt_seterr (wsp, rc);
      return 1;
    }

  if (value)
    {
      if (flg & _WSNF_QUOTE)
	{
	  if (wsnode_new (wsp, &newnode))
	    return 1;
	  wsnode_insert (wsp, newnode, *ptail, 0);
	  *ptail = newnode;
	  newnode->flags = _WSNF_WORD | _WSNF_NOEXPAND | flg;
	  newnode->v.word = value;
	}
      else if (*value == 0)
	{
	  free (value);
	  /* Empty string is a special case */
	  if (wsnode_new (wsp, &newnode))
	    return 1;
	  wsnode_insert (wsp, newnode, *ptail, 0);
	  *ptail = newnode;
	  newnode->flags = _WSNF_NULL | _WSNF_NOEXPAND;
	}
      else
	{
	  struct wordsplit ws;
	  int rc;

	  rc = _wsplt_subsplit (wsp, &ws, value, strlen (value),
				WRDSF_NOVAR | WRDSF_NOCMD
				| WRDSF_WS | WRDSF_QUOTE
				| (WSP_RETURN_DELIMS (wsp) ? WRDSF_RETURN_DELIMS : 0),
				0);
	  free (value);
	  if (rc)
	    {
	      _wsplt_seterr_sub (wsp, &ws);
	      wordsplit_free (&ws);
	      return 1;
	    }
	  wsnode_insert (wsp, ws.ws_head, *ptail, 0);
	  *ptail = ws.ws_tail;
	  ws.ws_head = ws.ws_tail = NULL;
	  wordsplit_free (&ws);
	}
    }
  else
    {
      if (wsnode_new (wsp, &newnode))
	return 1;
      wsnode_insert (wsp, newnode, *ptail, 0);
      *ptail = newnode;
      newnode->flags = _WSNF_NULL | _WSNF_NOEXPAND;
    }
  return 0;
}

static int
wordsplit_cmdexp (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p;)
    {
      struct wordsplit_node *next = p->next;
      if (!(p->flags & _WSNF_NOEXPAND))
	if (node_expand (wsp, p, begin_cmd_p, expcmd))
	  return 1;
      p = next;
    }

  wsnode_nullelim (wsp);
  return 0;
}

static int
wordsplit_trimws (struct wordsplit *wsp)
{
  struct wordsplit_node *p;

  for (p = wsp->ws_head; p; p = p->next)
    {
      size_t n;

      if (!(p->flags & _WSNF_QUOTE))
	{
	  /* Skip leading whitespace: */
	  for (n = p->v.segm.beg; n < p->v.segm.end && ISWS (wsp->ws_input[n]);
	       n++)
	    ;
	  p->v.segm.beg = n;
	}

      while (p->next && (p->flags & _WSNF_JOIN))
	p = p->next;

      if (p->flags & _WSNF_QUOTE)
	continue;

      /* Trim trailing whitespace */
      for (n = p->v.segm.end;
	   n > p->v.segm.beg && ISWS (wsp->ws_input[n - 1]); n--);
      p->v.segm.end = n;
      if (p->v.segm.beg == p->v.segm.end)
	p->flags |= _WSNF_NULL | _WSNF_NOEXPAND;
    }

  wsnode_nullelim (wsp);
  return 0;
}

static int
wordsplit_tildexpand (struct wordsplit *wsp)
{
  struct wordsplit_node *p;
  char *uname = NULL;
  size_t usize = 0;

  for (p = wsp->ws_head; p; p = p->next)
    {
      const char *str;

      if (p->flags & _WSNF_QUOTE)
	continue;

      str = wsnode_ptr (wsp, p);
      if (str[0] == '~')
	{
	  size_t i, size, dlen;
	  size_t slen = wsnode_len (p);
	  struct passwd *pw;
	  char *newstr;

	  for (i = 1; i < slen && str[i] != '/'; i++)
	    ;
	  if (i == slen)
	    continue;
	  if (i > 1)
	    {
	      if (i > usize)
		{
		  char *p = realloc (uname, i);
		  if (!p)
		    {
		      free (uname);
		      return _wsplt_nomem (wsp);
		    }
		  uname = p;
		  usize = i;
		}
	      --i;
	      memcpy (uname, str + 1, i);
	      uname[i] = 0;
	      pw = getpwnam (uname);
	    }
	  else
	    pw = getpwuid (getuid ());

	  if (!pw)
	    continue;

	  dlen = strlen (pw->pw_dir);
	  size = slen - i + dlen;
	  newstr = malloc (size);
	  if (!newstr)
	    {
	      free (uname);
	      return _wsplt_nomem (wsp);
	    }
	  --size;

	  memcpy (newstr, pw->pw_dir, dlen);
	  memcpy (newstr + dlen, str + i + 1, slen - i - 1);
	  newstr[size] = 0;
	  if (p->flags & _WSNF_WORD)
	    free (p->v.word);
	  p->v.word = newstr;
	  p->flags |= _WSNF_WORD;
	}
    }
  free (uname);
  return 0;
}

static int
isglob (const char *s, int l)
{
  while (l--)
    {
      if (strchr ("*?[", *s++))
	return 1;
    }
  return 0;
}

static int
wordsplit_pathexpand (struct wordsplit *wsp)
{
  struct wordsplit_node *p, *next;
  char *pattern = NULL;
  size_t patsize = 0;
  size_t slen;
  int flags = 0;

#ifdef GLOB_PERIOD
  if (wsp->ws_options & WRDSO_DOTGLOB)
    flags = GLOB_PERIOD;
#endif

  for (p = wsp->ws_head; p; p = next)
    {
      const char *str;

      next = p->next;

      if (p->flags & _WSNF_QUOTE)
	continue;

      str = wsnode_ptr (wsp, p);
      slen = wsnode_len (p);

      if (isglob (str, slen))
	{
	  int i;
	  glob_t g;
	  struct wordsplit_node *prev;

	  if (slen + 1 > patsize)
	    {
	      char *p = realloc (pattern, slen + 1);
	      if (!p)
		return _wsplt_nomem (wsp);
	      pattern = p;
	      patsize = slen + 1;
	    }
	  memcpy (pattern, str, slen);
	  pattern[slen] = 0;

	  switch (glob (pattern, flags, NULL, &g))
	    {
	    case 0:
	      break;

	    case GLOB_NOSPACE:
	      free (pattern);
	      return _wsplt_nomem (wsp);

	    case GLOB_NOMATCH:
	      if (wsp->ws_options & WRDSO_NULLGLOB)
		{
		  wsnode_remove (wsp, p);
		}
	      else if (wsp->ws_options & WRDSO_FAILGLOB)
		{
		  char buf[128];
		  if (wsp->ws_errno == WRDSE_USERERR)
		    free (wsp->ws_usererr);
		  snprintf (buf, sizeof (buf), _("no files match pattern %s"),
			    pattern);
		  free (pattern);
		  wsp->ws_usererr = strdup (buf);
		  if (!wsp->ws_usererr)
		    return _wsplt_nomem (wsp);
		  else
		    return _wsplt_seterr (wsp, WRDSE_USERERR);
		}
	      continue;

	    default:
	      free (pattern);
	      return _wsplt_setctxerr (wsp, WRDSE_GLOBERR, str, slen);
	    }

	  prev = p;
	  for (i = 0; i < g.gl_pathc; i++)
	    {
	      struct wordsplit_node *newnode;
	      char *newstr;

	      if (wsnode_new (wsp, &newnode))
		return 1;
	      newstr = strdup (g.gl_pathv[i]);
	      if (!newstr)
		return _wsplt_nomem (wsp);
	      newnode->v.word = newstr;
	      newnode->flags |= _WSNF_WORD|_WSNF_QUOTE;
	      wsnode_insert (wsp, newnode, prev, 0);
	      prev = newnode;
	    }
	  globfree (&g);

	  wsnode_remove (wsp, p);
	}
    }
  free (pattern);
  return 0;
}

static int
skip_sed_expr (const char *command, size_t i, size_t len)
{
  int state;

  do
    {
      int delim;

      if (command[i] == ';')
	i++;
      if (!(command[i] == 's' && i + 3 < len && ISPUNCT (command[i + 1])))
	break;

      delim = command[++i];
      state = 1;
      for (i++; i < len; i++)
	{
	  if (state == 3)
	    {
	      if (command[i] == delim || !ISALNUM (command[i]))
		break;
	    }
	  else if (command[i] == '\\')
	    i++;
	  else if (command[i] == delim)
	    state++;
	}
    }
  while (state == 3 && i < len && command[i] == ';');
  return i;
}

static inline size_t
skip_delim_internal (struct wordsplit *wsp, int return_delims)
{
  return return_delims ? wsp->ws_endp : wsp->ws_endp + 1;
}

static inline size_t
skip_delim (struct wordsplit *wsp)
{
  return skip_delim_internal (wsp, WSP_RETURN_DELIMS (wsp));
}

static inline size_t
skip_delim_real (struct wordsplit *wsp)
{
  return skip_delim_internal (wsp, wsp->ws_flags & WRDSF_RETURN_DELIMS);
}

static int
scan_qstring (struct wordsplit *wsp, size_t start, size_t *end)
{
  size_t j;
  const char *command = wsp->ws_input;
  size_t len = wsp->ws_len;
  char q = command[start];

  for (j = start + 1; j < len && command[j] != q; j++)
    if (q == '"' && command[j] == '\\')
      j++;
  if (j < len && command[j] == q)
    {
      int flags = _WSNF_QUOTE | _WSNF_EMPTYOK;
      if (q == '\'')
	flags |= _WSNF_NOEXPAND;
      if (wordsplit_add_segm (wsp, start + 1, j, flags))
	return _WRDS_ERR;
      *end = j;
    }
  else
    {
      wsp->ws_endp = start;
      _wsplt_seterr (wsp, WRDSE_QUOTE);
      return _WRDS_ERR;
    }
  return 0;
}

static int
scan_word (struct wordsplit *wsp, size_t start, int consume_all)
{
  size_t len = wsp->ws_len;
  const char *command = wsp->ws_input;
  const char *comment = wsp->ws_comment;
  int join = 0;
  int flags = 0;
  struct wordsplit_node *np = wsp->ws_tail;

  size_t i = start;

  if (i >= len)
    {
      wsp->ws_errno = WRDSE_EOF;
      return _WRDS_EOF;
    }

  start = i;

  if (wsp->ws_flags & WRDSF_SED_EXPR
      && command[i] == 's' && i + 3 < len && ISPUNCT (command[i + 1]))
    {
      flags = _WSNF_SEXP;
      i = skip_sed_expr (command, i, len);
    }
  else if (consume_all || !ISDELIM (wsp, command[i]))
    {
      while (i < len)
	{
	  if (comment && strchr (comment, command[i]) != NULL)
	    {
	      size_t j;
	      for (j = i + 1; j < len && command[j] != '\n'; j++)
		;
	      if (wordsplit_add_segm (wsp, start, i, 0))
		return _WRDS_ERR;
	      wsp->ws_endp = j;
	      return _WRDS_OK;
	    }

	  if (command[i] == '\\')
	    {
	      if (i + 1 == len)
		{
		  i++;
		  break;
		}
	      if (wsplt_unquote_char (wsp->ws_escape[WRDSX_WORD], command[i+1]))
		{
		  i += 2;
		  continue;
		}
	    }

	  if ((wsp->ws_flags & WRDSF_QUOTE) &&
	      (((wsp->ws_flags & WRDSF_SQUOTE) && command[i] == '\'') ||
	       ((wsp->ws_flags & WRDSF_DQUOTE) && command[i] == '"')))
	    {
	      if (join && wsp->ws_tail)
		wsp->ws_tail->flags |= _WSNF_JOIN;
	      if (wordsplit_add_segm (wsp, start, i, _WSNF_JOIN))
		return _WRDS_ERR;
	      if (scan_qstring (wsp, i, &i))
		return _WRDS_ERR;
	      start = i + 1;
	      join = 1;
	    }

	  if (command[i] == '$')
	    {
	      if ((!(wsp->ws_flags & WRDSF_NOVAR)
		   || (wsp->ws_options & WRDSO_NOVARSPLIT))
		  && command[i+1] == '{'
		  && find_closing_paren (command, i + 2, len, &i, "{}") == 0)
		continue;
	      if ((!(wsp->ws_flags & WRDSF_NOCMD)
		   || (wsp->ws_options & WRDSO_NOCMDSPLIT))
		  && command[i+1] == '('
		  && find_closing_paren (command, i + 2, len, &i, "()") == 0)
		continue;
	    }

	  if (!consume_all && ISDELIM (wsp, command[i]))
	    break;
	  else
	    i++;
	}
    }
  else if (WSP_RETURN_DELIMS (wsp))
    {
      i++;
      flags |= _WSNF_DELIM | _WSNF_NOEXPAND;
    }
  else if (!(wsp->ws_flags & WRDSF_SQUEEZE_DELIMS))
    flags |= _WSNF_EMPTYOK;

  if (join && i > start && wsp->ws_tail)
    wsp->ws_tail->flags |= _WSNF_JOIN;
  if (wordsplit_add_segm (wsp, start, i, flags))
    return _WRDS_ERR;
  wsp->ws_endp = i;
  if (wsp->ws_flags & WRDSF_INCREMENTAL)
    return _WRDS_EOF;

  if (consume_all)
    {
      if (!np)
	np = wsp->ws_head;
      while (np)
	{
	  np->flags |= _WSNF_QUOTE;
	  np = np->next;
	}
    }

  return _WRDS_OK;
}

static int
xtonum (int *pval, const char *src, int base, int cnt)
{
  int i, val;

  for (i = 0, val = 0; i < cnt; i++, src++)
    {
      int n = *(unsigned char *) src;
      if (n > 127 || (n = to_num (n)) >= base)
	break;
      val = val * base + n;
    }
  *pval = val;
  return i;
}

size_t
wordsplit_c_quoted_length (const char *str, int quote_hex, int *quote)
{
  size_t len = 0;

  *quote = 0;
  for (; *str; str++)
    {
      if (strchr (" \"", *str))
	*quote = 1;

      if (*str == ' ')
	len++;
      else if (*str == '"')
	len += 2;
      else if (*str != '\t' && *str != '\\' && ISPRINT (*str))
	len++;
      else if (quote_hex)
	len += 3;
      else
	{
	  if (wordsplit_c_quote_char (*str))
	    len += 2;
	  else
	    len += 4;
	}
    }
  return len;
}

static int
wsplt_unquote_char (const char *transtab, int c)
{
  while (*transtab && transtab[1])
    {
      if (*transtab++ == c)
	return *transtab;
      ++transtab;
    }
  return 0;
}

static int
wsplt_quote_char (const char *transtab, int c)
{
  for (; *transtab && transtab[1]; transtab += 2)
    {
      if (transtab[1] == c)
	return *transtab;
    }
  return 0;
}

int
wordsplit_c_unquote_char (int c)
{
  return wsplt_unquote_char (wordsplit_escape[WS_ESC_C], c);
}

int
wordsplit_c_quote_char (int c)
{
  return wsplt_quote_char (wordsplit_escape[WS_ESC_C], c);
}

void
wordsplit_string_unquote_copy (struct wordsplit *ws, int inquote,
			       char *dst, const char *src, size_t n)
{
  int i = 0;
  int c;

  inquote = !!inquote;
  while (i < n)
    {
      if (src[i] == '\\')
	{
	  ++i;
	  if (WRDSO_ESC_TEST (ws, inquote, WRDSO_XESC)
	      && (src[i] == 'x' || src[i] == 'X'))
	    {
	      if (n - i < 2)
		{
		  *dst++ = '\\';
		  *dst++ = src[i++];
		}
	      else
		{
		  int off = xtonum (&c, src + i + 1,
				    16, 2);
		  if (off == 0)
		    {
		      *dst++ = '\\';
		      *dst++ = src[i++];
		    }
		  else
		    {
		      *dst++ = c;
		      i += off + 1;
		    }
		}
	    }
	  else if (WRDSO_ESC_TEST (ws, inquote, WRDSO_OESC)
		   && (unsigned char) src[i] < 128 && ISDIGIT (src[i]))
	    {
	      if (n - i < 1)
		{
		  *dst++ = '\\';
		  *dst++ = src[i++];
		}
	      else
		{
		  int off = xtonum (&c, src + i, 8, 3);
		  if (off == 0)
		    {
		      *dst++ = '\\';
		      *dst++ = src[i++];
		    }
		  else
		    {
		      *dst++ = c;
		      i += off;
		    }
		}
	    }
	  else if ((c = wsplt_unquote_char (ws->ws_escape[inquote], src[i])))
	    {
	      *dst++ = c;
	      ++i;
	    }
	  else
	    {
	      if (WRDSO_ESC_TEST (ws, inquote, WRDSO_BSKEEP))
		*dst++ = '\\';
	      *dst++ = src[i++];
	    }
	}
      else
	*dst++ = src[i++];
    }
  *dst = 0;
}

void
wordsplit_c_quote_copy (char *dst, const char *src, int quote_hex)
{
  for (; *src; src++)
    {
      if (*src == '"')
	{
	  *dst++ = '\\';
	  *dst++ = *src;
	}
      else if (*src != '\t' && *src != '\\' && ISPRINT (*src))
	*dst++ = *src;
      else
	{
	  char tmp[4];

	  if (quote_hex)
	    {
	      snprintf (tmp, sizeof tmp, "%%%02X", *(unsigned char *) src);
	      memcpy (dst, tmp, 3);
	      dst += 3;
	    }
	  else
	    {
	      int c = wordsplit_c_quote_char (*src);
	      *dst++ = '\\';
	      if (c)
		*dst++ = c;
	      else
		{
		  snprintf (tmp, sizeof tmp, "%03o", *(unsigned char *) src);
		  memcpy (dst, tmp, 3);
		  dst += 3;
		}
	    }
	}
    }
}

static inline int
exptab_matches(struct exptab *p, struct wordsplit *wsp)
{
  int result;

  result = (wsp->ws_flags & p->flag);
  if (p->opt & EXPORT_ALLOF)
    result = result == p->flag;
  if (p->opt & EXPOPT_NEG)
    result = !result;

  return result;
}

static int
wordsplit_process_list (struct wordsplit *wsp, size_t start)
{
  struct exptab *p;

  if (wsp->ws_flags & WRDSF_SHOWDBG)
    wsp->ws_debug (_("(%02d) Input:%.*s;"),
		   wsp->ws_lvl, (int) wsp->ws_len, wsp->ws_input);

  if ((wsp->ws_flags & WRDSF_NOSPLIT)
      || ((wsp->ws_options & WRDSO_MAXWORDS)
	  && wsp->ws_wordi + 1 == wsp->ws_maxwords))
    {
      /* Treat entire input as a single word */
      if (scan_word (wsp, start, 1) == _WRDS_ERR)
	return wsp->ws_errno;
    }
  else
    {
      int rc;

      while ((rc = scan_word (wsp, start, 0)) == _WRDS_OK)
	start = skip_delim (wsp);
      /* Make sure tail element is not joinable */
      if (wsp->ws_tail)
	wsp->ws_tail->flags &= ~_WSNF_JOIN;
      if (rc == _WRDS_ERR)
	return wsp->ws_errno;
    }

  if (wsp->ws_flags & WRDSF_SHOWDBG)
    {
      wsp->ws_debug ("(%02d) %s", wsp->ws_lvl, _("Initial list:"));
      wordsplit_dump_nodes (wsp);
    }

  for (p = exptab; p->descr; p++)
    {
      if (exptab_matches(p, wsp))
	{
	  if (p->opt & EXPOPT_COALESCE)
	    {
	      if (wsnode_coalesce (wsp))
		break;
	      if (wsp->ws_flags & WRDSF_SHOWDBG)
		{
		  wsp->ws_debug ("(%02d) %s", wsp->ws_lvl,
				 _("Coalesced list:"));
		  wordsplit_dump_nodes (wsp);
		}
	    }
	  if (p->expansion)
	    {
	      if (p->expansion (wsp))
		break;
	      if (wsp->ws_flags & WRDSF_SHOWDBG)
		{
		  wsp->ws_debug ("(%02d) %s", wsp->ws_lvl, _(p->descr));
		  wordsplit_dump_nodes (wsp);
		}
	    }
	}
    }

  return wsp->ws_errno;
}

static int
wordsplit_run (const char *command, size_t length, struct wordsplit *wsp,
	       int flags, int lvl)
{
  int rc;
  size_t start;

  /* Initialize error context early */
  wsp->ws_errctx = NULL;
  if (!command)
    {
      if (!(flags & WRDSF_INCREMENTAL))
	{
	  /* Make sure _wsplt_seterr gets correct flags. */
	  wsp->ws_flags = flags;
	  return _wsplt_seterr (wsp, WRDSE_USAGE);
	}

      if (wsp->ws_head)
	return wordsplit_finish (wsp);

      start = skip_delim_real (wsp);
      if (wsp->ws_endp == wsp->ws_len)
	return _wsplt_seterr (wsp, WRDSE_NOINPUT);

      wsp->ws_flags |= WRDSF_REUSE;
      wordsplit_init0 (wsp);
    }
  else
    {
      start = 0;
      rc = wordsplit_init (wsp, command, length, flags);
      if (rc)
	return rc;
      wsp->ws_lvl = lvl;
    }

  rc = wordsplit_process_list (wsp, start);
  if (rc)
    return rc;
  return wordsplit_finish (wsp);
}

int
wordsplit_len (const char *command, size_t length, struct wordsplit *wsp,
	       int flags)
{
  return wordsplit_run (command, length, wsp, flags, 0);
}

int
wordsplit (const char *command, struct wordsplit *ws, int flags)
{
  return wordsplit_len (command, command ? strlen (command) : 0, ws, flags);
}

void
wordsplit_free_words (struct wordsplit *ws)
{
  size_t i;

  for (i = 0; i < ws->ws_wordc; i++)
    {
      char *p = ws->ws_wordv[ws->ws_offs + i];
      if (p)
	{
	  free (p);
	  ws->ws_wordv[ws->ws_offs + i] = NULL;
	}
    }
  ws->ws_wordc = 0;
}

void
wordsplit_free_envbuf (struct wordsplit *ws)
{
  if (!(ws->ws_flags & WRDSF_ENV))
    return;
  if (ws->ws_envbuf)
    {
      size_t i;

      for (i = 0; ws->ws_envbuf[i]; i++)
	free (ws->ws_envbuf[i]);
      free (ws->ws_envbuf);
      ws->ws_envidx = ws->ws_envsiz = 0;
      ws->ws_envbuf = NULL;
    }
}

void
wordsplit_free_parambuf (struct wordsplit *ws)
{
  if (!(ws->ws_options & WRDSO_PARAMV))
    return;
  if (ws->ws_parambuf)
    {
      size_t i;

      for (i = 0; ws->ws_parambuf[i]; i++)
	free (ws->ws_parambuf[i]);
      free (ws->ws_parambuf);
      ws->ws_paramidx = ws->ws_paramsiz = 0;
      ws->ws_parambuf = NULL;
    }
}

void
wordsplit_clearerr (struct wordsplit *ws)
{
  if (ws->ws_errno == WRDSE_USERERR)
    free (ws->ws_usererr);
  ws->ws_usererr = NULL;

  free (ws->ws_errctx);
  ws->ws_errctx = NULL;

  ws->ws_errno = WRDSE_OK;
}

void
wordsplit_free (struct wordsplit *ws)
{
  if (ws->ws_errno == WRDSE_USAGE)
    /* Usage error: the structure is not properly initialized and there's
       nothing to free. */
    return;
  wordsplit_clearerr (ws);
  wordsplit_free_nodes (ws);
  wordsplit_free_words (ws);
  free (ws->ws_wordv);
  ws->ws_wordv = NULL;
  wordsplit_free_envbuf (ws);
  wordsplit_free_parambuf (ws);
}

int
wordsplit_get_words (struct wordsplit *ws, size_t *wordc, char ***wordv)
{
  char **p = realloc (ws->ws_wordv,
		      (ws->ws_wordc + 1) * sizeof (ws->ws_wordv[0]));
  if (!p)
    return -1;
  *wordv = p;
  *wordc = ws->ws_wordc;

  ws->ws_wordv = NULL;
  ws->ws_wordc = 0;
  ws->ws_wordn = 0;

  return 0;
}

const char *
wordsplit_strerror (struct wordsplit *ws)
{
  if (ws->ws_errno == WRDSE_USERERR)
    return ws->ws_usererr;
  if (ws->ws_errno < _wordsplit_nerrs)
    return _wordsplit_errstr[ws->ws_errno];
  return N_("unknown error");
}

void
wordsplit_perror (struct wordsplit *wsp)
{
  switch (wsp->ws_errno)
    {
    case WRDSE_QUOTE:
      wsp->ws_error (_("missing closing %c (start near #%lu)"),
		     wsp->ws_input[wsp->ws_endp],
		     (unsigned long) wsp->ws_endp);
      break;

    default:
      if (wsp->ws_errctx)
	wsp->ws_error ("%s: %s", wordsplit_strerror (wsp), wsp->ws_errctx);
      else
	wsp->ws_error ("%s", wordsplit_strerror (wsp));
    }
}

